INSERT INTO "public"."adaptive_aptitude_responses" ("id", "session_id", "question_id", "selected_answer", "is_correct", "response_time_ms", "difficulty_at_time", "subtag", "phase", "sequence_number", "answered_at", "question_text", "question_options", "correct_answer", "explanation") VALUES
	('e484dabf-00b0-41a9-be98-f8b2a1e11854', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_diagnostic_screener_d3_data_interpretation_1769235679023_rsj26y', 'A', false, 55683, 3, 'data_interpretation', 'diagnostic_screener', 1, '2026-01-24 06:22:16.553764+00', 'Rohan collected data on the types of fruit his friends brought for lunch. The table shows the results: Apples: 8, Oranges: 5, Bananas: 7, Grapes: 4. What is the total number of fruits brought by his friends?', '{"A": "20", "B": "22", "C": "24", "D": "26"}', 'C', 'Add all the numbers: 8 + 5 + 7 + 4 = 24 fruits in total.'),
	('a018d2ab-c86f-4edc-a931-8fc920b5fa40', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_diagnostic_screener_d3_numerical_reasoning_1768544632477_hl304n', 'D', false, 3466, 3, 'numerical_reasoning', 'diagnostic_screener', 2, '2026-01-24 06:22:22.434817+00', 'If Priya scored 80% on her math test and the test had 50 questions, how many questions did she answer correctly?', '{"A": "30", "B": "35", "C": "40", "D": "45"}', 'C', 'To find the number of correct answers: 80% of 50 is 0.8 * 50 = 40.'),
	('ff7dea83-4bdf-4146-8b9c-10a3e66ff0b2', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_diagnostic_screener_d3_pattern_recognition_1768544121811_inj6b3', 'B', false, 3796, 3, 'pattern_recognition', 'diagnostic_screener', 3, '2026-01-24 06:22:27.909745+00', 'Ananya has a sequence of numbers: 2, 4, 8, 16. What is the next number in the pattern?', '{"A": "32", "B": "24", "C": "30", "D": "28"}', 'A', 'The pattern doubles each time: 16 × 2 = 32.'),
	('a5eb171c-c1b5-4f75-ba04-6e572c1b05c2', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_diagnostic_screener_d3_spatial_reasoning_1768539208241_8xffoa', 'D', false, 3114, 3, 'spatial_reasoning', 'diagnostic_screener', 4, '2026-01-24 06:22:33.158608+00', 'Rohan has a rectangular garden that is 10 meters long and 5 meters wide. What is the area of the garden?', '{"A": "15 square meters", "B": "25 square meters", "C": "50 square meters", "D": "75 square meters"}', 'C', 'The area is calculated by multiplying length and width: 10 m x 5 m = 50 square meters.'),
	('369343ed-ed12-4a24-a062-87850c8a9b6e', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_diagnostic_screener_d3_verbal_reasoning_1769235679023_5yzton', 'A', false, 8768, 3, 'verbal_reasoning', 'diagnostic_screener', 5, '2026-01-24 06:22:43.538411+00', 'Priya needs to find a word that has the same relationship as ''happy'' is to ''joyful''. Which word completes the analogy: ''sad'' is to ______?', '{"A": "happy", "B": "angry", "C": "unhappy", "D": "cheerful"}', 'C', 'The relationship is that ''joyful'' is a synonym for ''happy''. Similarly, ''unhappy'' is a synonym for ''sad''.'),
	('749754e2-f049-4f05-b162-4e179a802779', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_diagnostic_screener_d3_logical_reasoning_1768544121811_q9rv8o', 'A', true, 12442, 3, 'logical_reasoning', 'diagnostic_screener', 6, '2026-01-24 06:22:57.808409+00', 'Rohan has 60 marbles. If 25% of them are blue, how many blue marbles does he have?', '{"A": "15", "B": "10", "C": "20", "D": "25"}', 'A', '25% of 60 = 0.25 × 60 = 15 blue marbles.'),
	('162ca683-cde8-43d6-8b77-1b412779f462', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_spatial_reasoning_1768539257820_9tnn6n', 'A', true, 5422, 2, 'spatial_reasoning', 'adaptive_core', 7, '2026-01-24 06:23:08.358501+00', 'Kavya sees a triangle with angles of 30° and 60°. What is the measure of the third angle?', '{"A": "90°", "B": "60°", "C": "120°", "D": "30°"}', 'A', 'The sum of angles in a triangle is 180°. So, 180° - (30° + 60°) = 90°.'),
	('393aa21f-7178-4901-963e-2958ee374a11', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d3_spatial_reasoning_1768547464351_juek06', 'B', false, 3216, 3, 'spatial_reasoning', 'adaptive_core', 8, '2026-01-24 06:23:15.42569+00', 'Rohan has a rectangular garden that is 12 meters long and 8 meters wide. If he wants to increase the length by 25% and the width by 50%, what will be the new area of the garden in square meters?', '{"A": "120", "B": "144", "C": "180", "D": "192"}', 'D', 'New length = 12 + (25% of 12) = 12 + 3 = 15 meters. New width = 8 + (50% of 8) = 8 + 4 = 12 meters. Area = 15 * 12 = 180 square meters.'),
	('1bafe9c2-5685-4828-8e9a-604cddfa010d', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_logical_reasoning_1768623777163_nrk4pd', 'D', false, 2263, 2, 'logical_reasoning', 'adaptive_core', 9, '2026-01-24 06:23:26.683909+00', 'Priya has 12 marbles. She gives half of her marbles to Rohan and then gives 3 marbles to Ananya. How many marbles does Priya have left?', '{"A": "3", "B": "6", "C": "9", "D": "12"}', 'A', 'Priya starts with 12 marbles. She gives half (12/2 = 6) to Rohan, leaving her with 6. Then she gives 3 more to Ananya, so 6 - 3 = 3 marbles left.'),
	('d5d22fc2-ebd8-49e9-a341-592343f51733', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_spatial_reasoning_1768549579513_4b4r9a', 'D', false, 5364, 1, 'spatial_reasoning', 'adaptive_core', 10, '2026-01-24 06:23:44.002386+00', 'Rohan has a square piece of paper. If he cuts off one corner, how many corners does the paper have now?', '{"A": "3", "B": "4", "C": "5", "D": "6"}', 'C', 'A square has 4 corners. Cutting off one corner adds a new corner, so it now has 5 corners.'),
	('d8fa343d-35cf-44a3-8685-e7a13c16faba', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_verbal_reasoning_1768551337609_3hcn0p', 'C', false, 3106, 1, 'verbal_reasoning', 'adaptive_core', 11, '2026-01-24 06:23:49.618737+00', 'Riya has 4 stickers. Her friend gives her 2 more stickers. How many stickers does Riya have now?', '{"A": "6", "B": "5", "C": "4", "D": "8"}', 'A', 'Riya started with 4 stickers and received 2 more. 4 + 2 = 6 stickers in total.'),
	('56c08f4b-4169-47c6-9fbe-635a3693fb76', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_data_interpretation_1768539257820_t9c0ry', 'D', false, 2325, 1, 'data_interpretation', 'adaptive_core', 12, '2026-01-24 06:23:55.171539+00', 'In a pie chart, if 25% of the pie represents apples and the total pie is 40 pieces, how many pieces represent apples?', '{"A": "5", "B": "10", "C": "15", "D": "20"}', 'B', '25% of 40 is 0.25 × 40 = 10 pieces.'),
	('27f5f0b0-6596-4c5f-982c-547e6da6843c', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_logical_reasoning_1768539371570_64jiua', 'B', false, 2089, 1, 'logical_reasoning', 'adaptive_core', 13, '2026-01-24 06:24:00.867612+00', 'Aarav has 4 toy cars. If he buys 2 more toy cars, how many toy cars does he have now?', '{"A": "6", "B": "5", "C": "4", "D": "3"}', 'A', 'Aarav had 4 toy cars and bought 2 more, so 4 + 2 = 6 toy cars.'),
	('55b50988-30bc-4f9d-8103-f86aeade032e', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_data_interpretation_1768544755482_wd5695', 'C', false, 2298, 1, 'data_interpretation', 'adaptive_core', 14, '2026-01-24 06:24:06.750549+00', 'Rohan has 4 toy cars. He buys 3 more toy cars. How many toy cars does Rohan have now?', '{"A": "7", "B": "6", "C": "8", "D": "5"}', 'A', 'Rohan started with 4 toy cars and bought 3 more, so 4 + 3 = 7 toy cars in total.'),
	('ab63121c-a92e-46d6-8f28-8b53aa97f166', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_numerical_reasoning_1769235854519_hxswgr', 'B', false, 4471, 1, 'numerical_reasoning', 'adaptive_core', 15, '2026-01-24 06:24:19.731986+00', 'Priya has 12 stickers. She gives 4 stickers to her friend Rohan. How many stickers does Priya have left?', '{"A": "8", "B": "10", "C": "14", "D": "16"}', 'A', 'Subtracting 4 from 12 gives 8. Priya started with 12 and gave away 4, so 12 - 4 = 8.'),
	('914e82fb-f8ff-4d8a-aa1e-8e487760a83e', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_logical_reasoning_1769235865488_4kb0b8', 'C', true, 2302, 1, 'logical_reasoning', 'adaptive_core', 16, '2026-01-24 06:24:28.854832+00', 'Rohan is taller than Priya. Priya is taller than Ananya. Who is the tallest among the three?', '{"A": "Priya", "B": "Ananya", "C": "Rohan", "D": "They are all the same height"}', 'C', 'If Rohan is taller than Priya, and Priya is taller than Ananya, then Rohan must be the tallest.'),
	('5d941ce7-3e0b-498b-a60b-8d4fc215bdfb', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_spatial_reasoning_1769235875627_haz8el', 'B', true, 3412, 2, 'spatial_reasoning', 'adaptive_core', 17, '2026-01-24 06:24:40.382245+00', 'Rohan has a square-shaped picture frame. If he rotates the frame 90 degrees clockwise, which of the following shows the correct new orientation?', '{"A": "The top side becomes the left side.", "B": "The top side becomes the right side.", "C": "The top side becomes the bottom side.", "D": "The top side stays on top."}', 'B', 'Rotating a square 90 degrees clockwise moves the top side to the right side, the right side to the bottom, the bottom to the left, and the left to the top.'),
	('df5180ca-9d1f-4717-9398-114a56aa3fbf', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d3_data_interpretation_1768547919470_5ed8q0', 'B', true, 9100, 3, 'data_interpretation', 'adaptive_core', 18, '2026-01-24 06:24:52.57075+00', 'Aarav has a box of 60 toy cars. If 40% of them are red, how many toy cars are not red?', '{"A": "36", "B": "24", "C": "30", "D": "40"}', 'B', 'First, find the number of red cars: 40% of 60 = 0.4 * 60 = 24 red cars. Then, subtract from the total: 60 - 24 = 36 cars are not red.'),
	('0fae5bd8-b8d1-4e93-b995-575cf4909dd4', '4df4ba60-c8ef-4c7e-8c14-aa802edb4a6e', 'higher_secondary_adaptive_core_d1_numerical_reasoning_1769506549722_tey4io', 'C', false, 3098, 1, 'numerical_reasoning', 'adaptive_core', 18, '2026-01-27 09:35:53.622401+00', 'What is 15% of 80?', '{"A": "10", "B": "12", "C": "15", "D": "8"}', 'B', 'Fallback question'),
	('83c04628-abfb-4fb8-9ada-eb43c6281262', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d4_pattern_recognition_1768544684664_hv75dw', 'A', false, 25571, 4, 'pattern_recognition', 'adaptive_core', 19, '2026-01-24 06:25:23.024087+00', 'Kavya is arranging her collection of 48 toy cars in rows of 6. How many complete rows can she make?', '{"A": "6", "B": "7", "C": "8", "D": "9"}', 'C', '48 toy cars divided by 6 cars per row equals 8 complete rows.'),
	('88710795-abb6-404b-b57d-c9bbf98d2dc2', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d3_spatial_reasoning_1768621595652_xzg6wz', 'A', true, 18266, 3, 'spatial_reasoning', 'adaptive_core', 20, '2026-01-24 06:25:45.451375+00', 'Kavya is folding a square piece of paper in half diagonally. Then, she folds it in half again diagonally. What shape will she see if she cuts off the corner that is the intersection of all the folds and unfolds the paper completely?', '{"A": "Octagon", "B": "Hexagon", "C": "Square", "D": "Triangle"}', 'A', 'Folding a square in half diagonally twice results in a triangle with the corner being the intersection. Cutting off this corner removes a small triangle from each of the four layers. When unfolded, this creates an octagon (an 8-sided shape).'),
	('e34ebd0e-94d7-49b3-8445-00305a982afe', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_verbal_reasoning_1769235988457_lwaxc4', 'A', true, 3127, 1, 'verbal_reasoning', 'adaptive_core', 24, '2026-01-24 06:26:35.020181+00', 'Rohan has 12 pencils. He gives 4 pencils to his friend Priya. How many pencils does Rohan have left?', '{"A": "8", "B": "16", "C": "6", "D": "10"}', 'A', 'Rohan starts with 12 pencils and gives away 4. Subtracting 4 from 12 gives 8 pencils remaining.'),
	('130b0b39-0374-4cda-8ce8-5e79a46afcd4', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d3_logical_reasoning_1768544162585_afs40l', 'A', false, 7395, 3, 'logical_reasoning', 'adaptive_core', 36, '2026-01-24 06:29:49.484933+00', 'Rohan has 15 red marbles and 10 blue marbles. If he gives away 5 red marbles, what fraction of his remaining marbles are blue?', '{"A": "1/3", "B": "1/2", "C": "2/5", "D": "1/4"}', 'B', 'Rohan has 10 blue + (15 - 5) red = 10 + 10 = 20 total marbles. The fraction of blue marbles is 10/20 = 1/2.'),
	('6925dfc2-7745-44ca-abda-24b464def9f4', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_numerical_reasoning_1769236204657_zwc63z', 'B', false, 5161, 1, 'numerical_reasoning', 'adaptive_core', 38, '2026-01-24 06:30:10.878659+00', 'Priya has 8 marbles. She gives 3 marbles to her friend Rohan. How many marbles does Priya have left?', '{"A": "5", "B": "11", "C": "3", "D": "8"}', 'A', 'Priya started with 8 marbles and gave away 3, so 8 - 3 = 5 marbles remain.'),
	('b67880a7-6744-45c1-aeb8-5402106c80ad', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_spatial_reasoning_1769236243220_bitarc', 'C', false, 2829, 1, 'spatial_reasoning', 'adaptive_core', 41, '2026-01-24 06:30:46.815367+00', 'Priya has a square piece of paper. She folds it in half once to make a rectangle, then folds that rectangle in half again. What is the final shape?', '{"A": "A square", "B": "A rectangle", "C": "A triangle", "D": "A circle"}', 'B', 'Folding a square in half once makes a rectangle. Folding that rectangle in half again still results in a rectangle, just smaller.'),
	('70a11473-1a26-4e1a-a64a-57ce5c1bd0e6', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_pattern_recognition_1768547494691_ach3qa', 'A', true, 4079, 1, 'pattern_recognition', 'adaptive_core', 42, '2026-01-24 06:30:53.378124+00', 'Ananya has 4 toy cars. Her friend gives her 2 more toy cars. How many toy cars does Ananya have now?', '{"A": "6", "B": "5", "C": "7", "D": "8"}', 'A', 'Ananya starts with 4 toy cars and receives 2 more, so 4 + 2 = 6 toy cars.'),
	('7ae0ca77-ef7b-48c3-a7b5-eee1422eec8e', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_stability_confirmation_d2_data_interpretation_1768539422983_7bmjam', 'B', false, 2736, 1, 'data_interpretation', 'stability_confirmation', 47, '2026-01-24 06:31:31.18532+00', 'Aditya has 5 packs of crayons. Each pack contains 8 crayons. How many crayons does he have in total?', '{"A": "30", "B": "35", "C": "40", "D": "45"}', 'C', 'Aditya has 5 packs with 8 crayons each, so 5 x 8 = 40 crayons.'),
	('9b73a478-7f9d-4083-bbe7-b0c9ccce5acd', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d3_numerical_reasoning_1769756169070_syzwer', 'A', true, 16642, 3, 'numerical_reasoning', 'adaptive_core', 30, '2026-01-30 06:56:26.1857+00', 'A bakery sells cookies in packs of 6 or packs of 15. Sarah wants to buy exactly 51 cookies. What is the minimum number of packs she needs to buy?', '{"A": "4", "B": "5", "C": "6", "D": "7"}', 'A', 'Sarah can buy two packs of 15 (30 cookies) and three packs of 7 (21 cookies) for a total of 51 cookies. This would be 5 packs, but we want to minimize the number of packs. If she buys 1 pack of 15 (15 cookies), she needs 36 more cookies, which can be obtained by 6 packs of 6. This would be 7 packs, but we want to minimize the number of packs. If she buys 3 packs of 15 (45 cookies), she needs 6 more cookies, which can be obtained by 1 pack of 6. Thus, the minimum number of packs she needs to buy is 4.'),
	('10e35b70-0318-4a0d-8bb9-15f926d8b07f', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d3_spatial_reasoning_1769756212039_fb40ub', 'C', false, 88572, 2, 'spatial_reasoning', 'adaptive_core', 35, '2026-01-30 06:58:21.049725+00', 'A rectangular garden is 8 meters long and 6 meters wide. A path of 1 meter wide is built around the garden. What is the area of the path?', '{"A": "28 square meters", "B": "32 square meters", "C": "36 square meters", "D": "40 square meters"}', 'A', 'The garden with the path is 10 meters long and 8 meters wide. The area of the garden with the path is 80 square meters. The area of the garden is 48 square meters. Therefore, the area of the path is 80 - 48 = 32 square meters.'),
	('932321bd-0ad4-41ad-8cae-3e8c6a473d85', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_stability_d1_spatial_reasoning_1769756374487_7sux87', 'A', false, 2816, 1, 'spatial_reasoning', 'stability_confirmation', 48, '2026-01-30 06:59:50.962749+00', 'Which of the following figures is symmetrical?', '{"A": "A scalene triangle", "B": "A rectangle", "C": "A parallelogram", "D": "An irregular pentagon"}', 'B', 'A rectangle has two lines of symmetry, making it symmetrical.'),
	('5b51443b-7ef1-48cb-afaf-f2129248d502', '46eeaacd-c441-48ae-aedc-61ce30c151d0', 'higher_secondary_stability_dundefined_logical_reasoning_1769898453577_qe6uzu', 'B', true, 4212, 2, 'logical_reasoning', 'stability_confirmation', 12, '2026-01-31 22:27:42.92704+00', 'Which of the following is the odd one out in terms of spatial orientation?', '{"A": "Cube", "B": "Sphere", "C": "Cylinder", "D": "Pyramid"}', 'B', 'A sphere is the only shape with no edges or vertices, making it distinct from the others.'),
	('3d793ac6-7871-4d7f-844f-8b466500ef08', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d4_numerical_reasoning_1768549496456_dwnhqq', 'C', false, 2540, 4, 'numerical_reasoning', 'adaptive_core', 21, '2026-01-24 06:25:52.408312+00', 'Ananya has 80 marbles, and she wants to divide them equally among her 5 friends. After giving each friend an equal amount, she finds she has 10 marbles left. How many marbles did each friend receive?', '{"A": "14", "B": "16", "C": "18", "D": "20"}', 'B', 'If Ananya has 10 marbles left after giving away some, she must have given away 80 - 10 = 70 marbles. Dividing 70 by 5 friends means each friend gets 70 / 5 = 14 marbles.'),
	('4a96ae27-a7f0-4d6c-a064-a22cd9ab2987', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_verbal_reasoning_1768539257820_txqw6s', 'B', false, 4319, 2, 'verbal_reasoning', 'adaptive_core', 27, '2026-01-24 06:27:07.642606+00', 'Which word is a synonym for ''fast''?', '{"A": "Quick", "B": "Slow", "C": "Lazy", "D": "Dull"}', 'A', '''Quick'' is a synonym for ''fast''.'),
	('73423ca1-d00e-4f8b-aff7-ea5ce5340922', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_logical_reasoning_1769236063297_9claay', 'C', false, 67752, 2, 'logical_reasoning', 'adaptive_core', 31, '2026-01-24 06:28:53.296159+00', 'Rohan has 15 red marbles and 8 blue marbles. He gives 5 red marbles and 3 blue marbles to Priya. How many more red marbles than blue marbles does Rohan have now?', '{"A": "3", "B": "4", "C": "5", "D": "6"}', 'B', 'Rohan has 15-5=10 red marbles and 8-3=5 blue marbles. 10-5=5 more red marbles, but wait... 10-5=5. Let me recalculate: 10 red, 5 blue, so 10-5=5. But option B is 4. Let me check the numbers again. Actually, 15-5=10 red, 8-3=5 blue, so 10-5=5. Hmm, that gives 5. Let me think... maybe I made an error. Wait, the question asks ''how many more red marbles than blue marbles'' - that''s red minus blue: 10-5=5. But 5 is option C. Let me re-read... Oh! I see the issue. The numbers: 15 red, 8 blue. Give 5 red, 3 blue. Remaining: red = 15-5=10, blue = 8-3=5. Difference = 10-5=5. So answer should be C, not B. But I need to verify the calculation once more to be absolutely certain. Yes, 10 minus 5 equals 5. So the correct answer is C: 5.'),
	('aa3874ef-cdf4-4fd7-80e2-cb09473bc579', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_numerical_reasoning_1769236233893_pmsu25', 'C', false, 3414, 1, 'numerical_reasoning', 'adaptive_core', 40, '2026-01-24 06:30:38.221625+00', 'Priya has 12 pencils. She gives 4 pencils to her friend. How many pencils does Priya have left?', '{"A": "8", "B": "16", "C": "6", "D": "10"}', 'A', 'Priya started with 12 pencils and gave away 4. To find how many she has left, subtract 4 from 12: 12 - 4 = 8.'),
	('5ab17798-3bbb-46e2-a2c2-4cb1932b94f7', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d4_logical_reasoning_1769756189459_gqxpi9', 'D', false, 4749, 4, 'logical_reasoning', 'adaptive_core', 31, '2026-01-30 06:56:34.627574+00', 'All athletes at Oakwood Middle School must maintain a B average. Sarah is an athlete at Oakwood. Which of the following statements MUST be true?', '{"A": "Sarah enjoys playing sports.", "B": "Sarah has good attendance in all her classes.", "C": "Sarah maintains at least a B average in her classes.", "D": "Sarah is the best athlete at Oakwood."}', 'C', 'The question states that ALL athletes must maintain a B average. Since Sarah is an athlete, she MUST maintain at least a B average. The other options are possible, but not necessarily true.'),
	('795b30ff-998f-496a-983f-4f7acc9573d8', '46eeaacd-c441-48ae-aedc-61ce30c151d0', 'higher_secondary_stability_dundefined_verbal_reasoning_1769898453577_8e4wal', 'B', false, 1923, 2, 'verbal_reasoning', 'stability_confirmation', 13, '2026-01-31 22:27:45.865587+00', 'In a data set, if the mode is 15, the median is 18, and the mean is 20, which statement is true?', '{"A": "The data set is positively skewed", "B": "The data set is negatively skewed", "C": "The data set is symmetrical", "D": "Insufficient information to determine skewness"}', 'A', 'When mean > median > mode, the data is positively skewed.'),
	('9d098007-e379-43e0-a851-77a6ae378abf', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d3_data_interpretation_1769235961163_phtvjy', 'C', false, 4214, 3, 'data_interpretation', 'adaptive_core', 22, '2026-01-24 06:26:07.097358+00', 'Priya tracked her reading over a week. The bar graph shows: Monday: 25 pages, Tuesday: 30 pages, Wednesday: 20 pages, Thursday: 35 pages, Friday: 15 pages. What was the average number of pages Priya read per day?', '{"A": "20 pages", "B": "25 pages", "C": "28 pages", "D": "30 pages"}', 'B', 'Add the pages: 25+30+20+35+15 = 125 pages. Divide by 5 days: 125 ÷ 5 = 25 pages per day.'),
	('7dec0a04-8a49-4883-9be7-a2c39e6db2dc', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_logical_reasoning_1769235976024_kk5tyj', 'D', false, 2269, 2, 'logical_reasoning', 'adaptive_core', 23, '2026-01-24 06:26:19.274444+00', 'Priya has 15 red marbles and 10 blue marbles. She gives 5 red marbles to her friend. How many more red marbles than blue marbles does she have now?', '{"A": "5", "B": "10", "C": "15", "D": "20"}', 'A', 'Priya has 15 - 5 = 10 red marbles left. She has 10 blue marbles. The difference is 10 - 10 = 0, but the question asks for ''more red than blue''. Since she has equal numbers, she has 0 more red marbles, but 5 is the correct answer because 10 red - 5 given = 5 remaining red, and 5 - 10 blue = -5, meaning 5 fewer red. The difference is 5 (10 red - 5 blue = 5).'),
	('90221f59-1fb0-41e1-8c55-92873f6af187', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_numerical_reasoning_1769236152670_370a1z', 'D', false, 5236, 1, 'numerical_reasoning', 'adaptive_core', 33, '2026-01-24 06:29:18.961891+00', 'Priya has 12 pencils. She gives 4 pencils to her friend. How many pencils does Priya have now?', '{"A": "8", "B": "16", "C": "6", "D": "10"}', 'A', 'Priya started with 12 pencils and gave away 4. So, 12 - 4 = 8 pencils remaining.'),
	('1cf027e8-3ebb-4140-9f57-8ad2c0313559', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d3_data_interpretation_1769756198403_xqdyru', 'C', false, 3564, 3, 'data_interpretation', 'adaptive_core', 32, '2026-01-30 06:56:42.361709+00', 'A school bake sale tracked the number of cookies sold each day. On Monday, 45 cookies were sold. On Tuesday, 60 cookies were sold. On Wednesday, 51 cookies were sold. On Thursday, 36 cookies were sold. If the goal was to sell an average of 50 cookies per day, how many cookies must be sold on Friday to meet the goal?', '{"A": "58", "B": "50", "C": "63", "D": "53"}', 'A', 'To average 50 cookies over 5 days, a total of 50*5 = 250 cookies must be sold. So far, 45 + 60 + 51 + 36 = 192 cookies have been sold. Therefore, 250 - 192 = 58 cookies must be sold on Friday.'),
	('e1db0d14-b8ed-4c57-aeef-fb49df66d44b', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_pattern_recognition_1768734956602_h3v6x9', 'C', true, 4332, 2, 'pattern_recognition', 'adaptive_core', 25, '2026-01-24 06:26:43.751882+00', 'Priya noticed a pattern in the number of stickers she collected each day: Monday: 5, Tuesday: 8, Wednesday: 11, Thursday: 14. How many stickers will she collect on Friday if the pattern continues?', '{"A": "15", "B": "16", "C": "17", "D": "18"}', 'C', 'The pattern adds 3 stickers each day (5→8→11→14). Following this, Friday''s count would be 14 + 3 = 17 stickers.'),
	('62004998-44a7-4f38-a83f-f7a06d6997e0', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d3_data_interpretation_1769756198403_xqdyru', 'A', true, 9761, 2, 'data_interpretation', 'adaptive_core', 33, '2026-01-30 06:56:48.592576+00', 'A school bake sale tracked the number of cookies sold each day. On Monday, 45 cookies were sold. On Tuesday, 60 cookies were sold. On Wednesday, 51 cookies were sold. On Thursday, 36 cookies were sold. If the goal was to sell an average of 50 cookies per day, how many cookies must be sold on Friday to meet the goal?', '{"A": "58", "B": "50", "C": "63", "D": "53"}', 'A', 'To average 50 cookies over 5 days, a total of 50*5 = 250 cookies must be sold. So far, 45 + 60 + 51 + 36 = 192 cookies have been sold. Therefore, 250 - 192 = 58 cookies must be sold on Friday.'),
	('209b61eb-92bf-4ed4-bbba-b52199022cc1', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d2_verbal_reasoning_1769756338387_7jdopl', 'C', false, 1341, 2, 'verbal_reasoning', 'adaptive_core', 39, '2026-01-30 06:59:00.096109+00', 'A baker is to bread as a sculptor is to:', '{"A": "Oven", "B": "Clay", "C": "Hammer", "D": "Statue"}', 'D', 'A baker creates bread, and a sculptor creates a statue. Therefore, the relationship is creator to creation.'),
	('b469944a-f345-4edd-aabd-c028e41f0547', '46eeaacd-c441-48ae-aedc-61ce30c151d0', 'higher_secondary_stability_dundefined_spatial_reasoning_1769898453577_ghv628', 'C', false, 1838, 2, 'spatial_reasoning', 'stability_confirmation', 14, '2026-01-31 22:27:48.767906+00', 'Which word does not belong in the group?', '{"A": "Guitar", "B": "Piano", "C": "Flute", "D": "Drum"}', 'A', 'The guitar is a string instrument, while the others are percussion instruments.'),
	('eece3a4a-2730-4ae7-964a-903a626d32c3', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d3_data_interpretation_1769236015672_7rs2i3', 'B', false, 2102, 3, 'data_interpretation', 'adaptive_core', 26, '2026-01-24 06:26:59.112633+00', 'Priya is organizing her bookshelf. She has 48 books total. 1/4 of them are science fiction, 1/3 are adventure stories, and the rest are mystery novels. How many mystery novels does Priya have?', '{"A": "8", "B": "12", "C": "16", "D": "20"}', 'C', 'First find science fiction books: 48 × 1/4 = 12. Adventure books: 48 × 1/3 = 16. Total of these two types: 12 + 16 = 28. Mystery novels: 48 - 28 = 20. Wait, 48 - 28 = 20, not 16. Let me recalculate: 1/4 of 48 is 12, 1/3 of 48 is 16, total 28, 48 - 28 = 20. Actually 20 is not an option. Let me check the fractions: 1/4 + 1/3 = 3/12 + 4/12 = 7/12. So mystery novels are 5/12 of 48. 5/12 × 48 = 5 × 4 = 20. But 20 is not an option. Wait, I need to check the math again. 1/4 of 48 = 12, 1/3 of 48 = 16, 12 + 16 = 28, 48 - 28 = 20. But 20 is not an option. Let me recalculate: 48 ÷ 4 = 12, 48 ÷ 3 = 16, 12 + 16 = 28, 48 - 28 = 20. Hmm, but 20 is not listed. Let me check the options: A: 8, B: 12, C: 16, D: 20. Wait, D is 20! So the answer should be D: 20. Let me verify: 1/4 of 48 = 12 science fiction, 1/3 of 48 = 16 adventure, total 28, remaining = 48 - 28 = 20 mystery novels. Yes, D is correct.'),
	('714ae5ed-ca6c-4154-8f24-7f41f83317e3', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_numerical_reasoning_1769236034892_aye1fd', 'C', false, 2185, 1, 'numerical_reasoning', 'adaptive_core', 28, '2026-01-24 06:27:17.933027+00', 'Priya has 12 stickers. She gives 4 stickers to her friend and then buys 7 more stickers. How many stickers does she have now?', '{"A": "15", "B": "23", "C": "19", "D": "11"}', 'A', 'Start with 12, subtract 4 (12 - 4 = 8), then add 7 (8 + 7 = 15).'),
	('54552da8-3dfd-47b9-85b6-b2ba65433781', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_data_interpretation_1769236194956_b8q31f', 'A', false, 2819, 2, 'data_interpretation', 'adaptive_core', 37, '2026-01-24 06:29:58.850552+00', 'Priya is selling handmade stickers at the school fair. She sold 15 stickers on Friday, 22 stickers on Saturday, and 18 stickers on Sunday. How many more stickers did she sell on Saturday than on Friday?', '{"A": "5", "B": "7", "C": "10", "D": "15"}', 'B', 'Subtract Friday''s sales from Saturday''s sales: 22 - 15 = 7'),
	('a8a7ef24-c13c-4678-a576-518759ad5cf9', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_spatial_reasoning_1768539409992_eej38i', 'D', false, 10422, 1, 'spatial_reasoning', 'adaptive_core', 39, '2026-01-24 06:30:24.204037+00', 'Rohan has 4 red balls and 2 blue balls. If he gives away 1 red ball, how many balls does he have left?', '{"A": "5", "B": "6", "C": "7", "D": "8"}', 'B', 'Rohan originally has 4 red + 2 blue = 6 balls. After giving away 1 red ball, he has 6 - 1 = 5 balls.'),
	('f7b68e42-1a9d-49db-83db-8ee2032b661c', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_stability_confirmation_d2_logical_reasoning_1768624844991_eel6gg', 'A', false, 2616, 1, 'logical_reasoning', 'stability_confirmation', 48, '2026-01-24 06:31:35.5522+00', 'Priya has three boxes. Box A is heavier than Box B. Box C is lighter than Box B. Which box is the lightest?', '{"A": "Box A", "B": "Box B", "C": "Box C", "D": "Cannot be determined"}', 'C', 'From the statements: Box A > Box B and Box C < Box B. Therefore, the order is Box A > Box B > Box C, making Box C the lightest.'),
	('627359d0-c0a2-4098-88aa-bad6bd35e300', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d3_spatial_reasoning_1769756212039_fb40ub', 'B', false, 2225, 3, 'spatial_reasoning', 'adaptive_core', 34, '2026-01-30 06:56:54.666907+00', 'A rectangular garden is 8 meters long and 6 meters wide. A path of 1 meter wide is built around the garden. What is the area of the path?', '{"A": "28 square meters", "B": "32 square meters", "C": "36 square meters", "D": "40 square meters"}', 'A', 'The garden with the path is 10 meters long and 8 meters wide. The area of the garden with the path is 80 square meters. The area of the garden is 48 square meters. Therefore, the area of the path is 80 - 48 = 32 square meters.'),
	('5bad7b64-94fe-483d-952d-77c8fbbbd8d9', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_diagnostic_d3_numerical_reasoning_1769899538458_zelw6c', 'C', false, 6764, 3, 'numerical_reasoning', 'diagnostic_screener', 1, '2026-01-31 22:45:45.790546+00', 'If x + 5 = 12, what is the value of x?', '{"A": "4", "B": "5", "C": "6", "D": "7"}', 'A', 'Subtracting 5 from 12 gives x = 7 - 5 = 4.'),
	('e4f8b87d-714e-4ed7-9cf9-dac3386e1f3b', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_verbal_reasoning_1769236043938_2lsuaf', 'B', false, 1911, 1, 'verbal_reasoning', 'adaptive_core', 29, '2026-01-24 06:27:26.836006+00', 'Priya has 8 pencils. She gives 3 pencils to her friend Rohan. How many pencils does Priya have now?', '{"A": "5", "B": "8", "C": "11", "D": "3"}', 'A', 'Priya starts with 8 pencils and gives away 3, so 8 - 3 = 5 pencils remain.'),
	('817a915a-c8ba-4fe4-a99f-19164bc60663', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d1_logical_reasoning_1769756304783_x25v4v', 'B', false, 1732, 1, 'logical_reasoning', 'adaptive_core', 36, '2026-01-30 06:58:26.939334+00', 'All cats like to nap. Max is a cat. Therefore, which statement must be true?', '{"A": "Max dislikes naps.", "B": "Max is a dog.", "C": "Max likes to nap.", "D": "All cats are named Max."}', 'C', 'Since all cats like to nap, and Max is a cat, it logically follows that Max likes to nap.'),
	('8bdcf4d3-5075-480e-9e67-0fee26e21000', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d1_spatial_reasoning_1769756352031_83eceq', 'B', false, 1823, 1, 'spatial_reasoning', 'adaptive_core', 42, '2026-01-30 06:59:14.364812+00', 'A square piece of paper is folded in half to make a rectangle. If the perimeter of the rectangle is 18 inches, what was the perimeter of the original square?', '{"A": "12 inches", "B": "18 inches", "C": "24 inches", "D": "36 inches"}', 'C', 'Let the side of the square be ''s''. Folding it in half makes a rectangle with sides ''s'' and ''s/2''. The perimeter of the rectangle is 2(s + s/2) = 18. So, 2(3s/2) = 18, which means 3s = 18, and s = 6. The perimeter of the original square is 4s = 4 * 6 = 24 inches.'),
	('c4c4e364-1a8b-40f2-a655-e525b4284b81', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d1_verbal_reasoning_1769756356797_bnvl8j', 'B', true, 3000, 1, 'verbal_reasoning', 'adaptive_core', 43, '2026-01-30 06:59:20.146063+00', 'Which word describes someone who always tells the truth?', '{"A": "Deceitful", "B": "Honest", "C": "Sly", "D": "Tricky"}', 'B', 'Honest means telling the truth and not lying.'),
	('9dc6d113-e031-45e1-9f34-7c0c45e62b8e', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d2_logical_reasoning_1769756363022_m8jtz9', 'B', false, 4307, 2, 'logical_reasoning', 'adaptive_core', 44, '2026-01-30 06:59:27.704129+00', 'All students in the Art Club are creative. Maya is in the Art Club. Which statement must be true?', '{"A": "Maya is good at math.", "B": "Maya likes to paint.", "C": "Maya is creative.", "D": "Maya is also in the Science Club."}', 'C', 'Since all members of the Art Club are creative, and Maya is in the Art Club, it logically follows that Maya is creative.'),
	('acb7eba9-1902-4f4f-9c6a-184e4a1d360d', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_diagnostic_d3_logical_reasoning_1769899538458_zq95f1', 'B', false, 2223, 3, 'logical_reasoning', 'diagnostic_screener', 2, '2026-01-31 22:45:49.132408+00', 'Which number comes next in the series: 2, 5, 10, 17, ...?', '{"A": "25", "B": "26", "C": "27", "D": "28"}', 'C', 'The series follows a pattern of adding consecutive odd numbers.'),
	('25b7f706-4190-43d5-bbc4-8bf49c97a5ef', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_data_interpretation_1768547568230_2xqu0u', 'A', true, 2749, 1, 'data_interpretation', 'adaptive_core', 30, '2026-01-24 06:27:35.070037+00', 'Rohan has 4 toy cars. His friend gives him 2 more. How many toy cars does Rohan have now?', '{"A": "6", "B": "3", "C": "5", "D": "8"}', 'A', 'Rohan started with 4 toy cars and received 2 additional toy cars. So, 4 + 2 = 6.'),
	('6a4e6559-8837-41f0-bed1-3763d5b920a3', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_verbal_reasoning_1769236139018_276a5o', 'B', false, 8219, 1, 'verbal_reasoning', 'adaptive_core', 32, '2026-01-24 06:29:07.911645+00', 'Rohan has 8 marbles. He gives 3 marbles to his friend Priya. How many marbles does Rohan have left?', '{"A": "5", "B": "11", "C": "3", "D": "8"}', 'A', 'Rohan started with 8 marbles and gave away 3, so 8 - 3 = 5 marbles remain.'),
	('b96dd528-e0d7-42f2-a942-cf6e2691c48c', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_stability_confirmation_d1_logical_reasoning_1769236278553_44c7jr', 'D', false, 3621, 1, 'logical_reasoning', 'stability_confirmation', 46, '2026-01-24 06:31:27.075404+00', 'Priya has a red ball and a blue ball. The red ball is larger than the blue ball. Which statement is definitely true?', '{"A": "The blue ball is larger than the red ball.", "B": "The red ball is smaller than the blue ball.", "C": "The red ball is larger than the blue ball.", "D": "Both balls are the same size."}', 'C', 'The statement says the red ball is larger than the blue ball, so that is the only true fact we know for sure.'),
	('e775b5f7-7033-4cc9-ac4b-1d0a159765b7', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d1_spatial_reasoning_1769756310202_ow675h', 'A', false, 7951, 1, 'spatial_reasoning', 'adaptive_core', 37, '2026-01-30 06:58:38.56608+00', 'A square piece of paper is folded in half to make a rectangle. The rectangle''s shorter side is 5 cm. What is the area of the original square?', '{"A": "20 sq cm", "B": "25 sq cm", "C": "50 sq cm", "D": "100 sq cm"}', 'D', 'If the shorter side of the rectangle is 5 cm, then the side of the original square was 2 * 5 = 10 cm. The area of the square is 10 * 10 = 100 sq cm.'),
	('619fdbed-be8e-4fde-95a2-fbdf3a4908f3', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_diagnostic_d3_verbal_reasoning_1769899538458_hfh8cn', 'C', true, 2277, 3, 'verbal_reasoning', 'diagnostic_screener', 3, '2026-01-31 22:45:52.574381+00', 'If all blorps are razzles, and some razzles are dingles, then...', '{"A": "all blorps are dingles", "B": "no blorps are dingles", "C": "some blorps are dingles", "D": "none of the above"}', 'C', 'From the statements, it can be deduced that some blorps are dingles.'),
	('83815eb5-905b-4c00-9428-2ee9cd0a2e68', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_core_d2_numerical_reasoning_1769899584701_8xsv4d', 'B', true, 4444, 2, 'numerical_reasoning', 'adaptive_core', 9, '2026-01-31 22:46:29.633193+00', 'If a circle has a radius of 5 cm, what is its diameter?', '{"A": "5 cm", "B": "10 cm", "C": "15 cm", "D": "25 cm"}', 'B', 'The diameter of a circle is twice the radius, so it is 10 cm.'),
	('230f8f94-4a09-4452-bd0c-00fddd03748d', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_data_interpretation_1769236164916_mexx75', 'B', true, 2828, 1, 'data_interpretation', 'adaptive_core', 34, '2026-01-24 06:29:29.201635+00', 'Priya made a bar chart showing how many books she read each week. In Week 1 she read 4 books, Week 2 she read 6 books, and Week 3 she read 5 books. How many books did she read in total over the 3 weeks?', '{"A": "12 books", "B": "15 books", "C": "18 books", "D": "20 books"}', 'B', 'Add the books from each week: 4 + 6 + 5 = 15 books total.'),
	('8552dcb4-294e-4031-95bc-d6da37a81a84', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_pattern_recognition_1768539257820_dzow9n', 'A', true, 4028, 2, 'pattern_recognition', 'adaptive_core', 35, '2026-01-24 06:29:38.438011+00', 'If a pattern starts with the numbers 2, 4, 6, what are the next two numbers?', '{"A": "8, 10", "B": "7, 9", "C": "5, 7", "D": "10, 12"}', 'A', 'The pattern increases by 2 each time: 2, 4, 6, 8, 10.'),
	('4d1baf1c-ef30-44bf-85c4-de20ab220d6a', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d1_logical_reasoning_1769236268330_l88iic', 'D', false, 2552, 1, 'logical_reasoning', 'adaptive_core', 44, '2026-01-24 06:31:12.108952+00', 'Priya has 8 red marbles and 5 blue marbles. She gives 3 marbles to her friend. How many marbles does Priya have left?', '{"A": "10", "B": "13", "C": "11", "D": "15"}', 'A', 'Priya starts with 8 + 5 = 13 marbles. After giving away 3, she has 13 - 3 = 10 marbles left.'),
	('f645327b-dba6-4e59-835b-f419978c1ed8', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_stability_confirmation_d1_pattern_recognition_1768547577552_lh7yqd', 'A', true, 2498, 1, 'pattern_recognition', 'stability_confirmation', 45, '2026-01-24 06:31:22.251607+00', 'If Rohan has 10 marbles and gives away 3, how many marbles does he have left?', '{"A": "7", "B": "6", "C": "5", "D": "8"}', 'A', 'Rohan starts with 10 marbles and gives away 3, so 10 - 3 = 7 marbles left.'),
	('00cc5b32-ba2d-406a-8d5c-add7bfca5910', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d1_logical_reasoning_1769756321946_nfx8l0', 'B', true, 12936, 1, 'logical_reasoning', 'adaptive_core', 38, '2026-01-30 06:58:55.370288+00', 'All students in Mrs. Smith''s class like to read. Sarah is in Mrs. Smith''s class. Which statement must be true?', '{"A": "Sarah likes to play sports.", "B": "Sarah likes to read.", "C": "Sarah likes to draw.", "D": "Sarah likes to eat pizza."}', 'B', 'Since all students in Mrs. Smith''s class like to read, and Sarah is in the class, it must be true that Sarah likes to read.'),
	('5676190e-b34c-4b35-a38c-e83e25c1f9fe', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d2_numerical_reasoning_1769756347312_3g9awl', 'C', false, 1309, 2, 'numerical_reasoning', 'adaptive_core', 41, '2026-01-30 06:59:08.991154+00', 'A bakery sells cookies in packs of 6. If a customer buys 4 packs and gives half of the cookies to their friend, how many cookies do they have left?', '{"A": "6", "B": "12", "C": "18", "D": "24"}', 'B', 'The customer buys 4 packs * 6 cookies/pack = 24 cookies. Half of 24 is 24 / 2 = 12 cookies.'),
	('7a1b6cc1-4bea-4277-a3b2-593254ad95f2', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_diagnostic_d3_spatial_reasoning_1769899538458_e9866a', 'A', false, 3643, 3, 'spatial_reasoning', 'diagnostic_screener', 4, '2026-01-31 22:45:57.337862+00', 'In a 3D grid, how many faces does a cube have?', '{"A": "4", "B": "6", "C": "8", "D": "12"}', 'B', 'A cube has 6 faces: front, back, top, bottom, left, and right.'),
	('c2ffc98f-13e0-4593-a51d-2867f31d61b2', 'ce3412ec-b268-43d2-951d-00dd210ddc65', 'middle_school_adaptive_core_d2_numerical_reasoning_1768539257820_r71jt2', 'D', false, 5808, 2, 'numerical_reasoning', 'adaptive_core', 43, '2026-01-24 06:31:03.268896+00', 'Priya has 150 stickers. She gives away 20% of them to her friends. How many stickers does she have left?', '{"A": "120", "B": "130", "C": "140", "D": "150"}', 'B', '20% of 150 is 30. So, 150 - 30 = 120 stickers left.'),
	('3dcba3bd-b8bd-4911-ae3d-ad8a76ecc5e4', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_diagnostic_d3_data_interpretation_1769899538458_lzf7qw', 'C', false, 2136, 3, 'data_interpretation', 'diagnostic_screener', 5, '2026-01-31 22:46:00.581657+00', 'What is the median of the following set of numbers: 12, 15, 18, 21, 24?', '{"A": "15", "B": "18", "C": "21", "D": "24"}', 'B', 'The numbers are already in ascending order, so the median is the middle number, which is 18.'),
	('4f051c19-df92-4ec2-9ad9-2ae50895fff4', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_diagnostic_screener_d3_data_interpretation_1769235679023_rsj26y', 'C', true, 24226, 3, 'data_interpretation', 'diagnostic_screener', 1, '2026-01-26 05:02:42.024196+00', 'Rohan collected data on the types of fruit his friends brought for lunch. The table shows the results: Apples: 8, Oranges: 5, Bananas: 7, Grapes: 4. What is the total number of fruits brought by his friends?', '{"A": "20", "B": "22", "C": "24", "D": "26"}', 'C', 'Add all the numbers: 8 + 5 + 7 + 4 = 24 fruits in total.'),
	('388de536-1327-43fb-b8ab-edb555ea6689', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_diagnostic_screener_d3_numerical_reasoning_1768544632477_hl304n', 'C', true, 18755, 3, 'numerical_reasoning', 'diagnostic_screener', 2, '2026-01-26 05:03:02.499374+00', 'If Priya scored 80% on her math test and the test had 50 questions, how many questions did she answer correctly?', '{"A": "30", "B": "35", "C": "40", "D": "45"}', 'C', 'To find the number of correct answers: 80% of 50 is 0.8 * 50 = 40.'),
	('a0317eea-ac23-492c-8b33-4d6ef7bd248b', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_diagnostic_screener_d3_spatial_reasoning_1768539208241_8xffoa', 'C', true, 19644, 3, 'spatial_reasoning', 'diagnostic_screener', 3, '2026-01-26 05:03:23.29723+00', 'Rohan has a rectangular garden that is 10 meters long and 5 meters wide. What is the area of the garden?', '{"A": "15 square meters", "B": "25 square meters", "C": "50 square meters", "D": "75 square meters"}', 'C', 'The area is calculated by multiplying length and width: 10 m x 5 m = 50 square meters.'),
	('6f72b240-68a7-4f19-bc40-a6cb2d4b4a5e', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_diagnostic_screener_d3_logical_reasoning_1768544121811_q9rv8o', 'A', true, 27059, 3, 'logical_reasoning', 'diagnostic_screener', 4, '2026-01-26 05:03:51.042431+00', 'Rohan has 60 marbles. If 25% of them are blue, how many blue marbles does he have?', '{"A": "15", "B": "10", "C": "20", "D": "25"}', 'A', '25% of 60 = 0.25 × 60 = 15 blue marbles.'),
	('c130fe7e-6b34-44e7-a53c-cf254fcba333', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_diagnostic_screener_d3_verbal_reasoning_1769235679023_5yzton', 'C', true, 26375, 3, 'verbal_reasoning', 'diagnostic_screener', 5, '2026-01-26 05:04:18.55469+00', 'Priya needs to find a word that has the same relationship as ''happy'' is to ''joyful''. Which word completes the analogy: ''sad'' is to ______?', '{"A": "happy", "B": "angry", "C": "unhappy", "D": "cheerful"}', 'C', 'The relationship is that ''joyful'' is a synonym for ''happy''. Similarly, ''unhappy'' is a synonym for ''sad''.'),
	('dd4f3ea4-f1c1-420a-bed2-343271cf7310', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_diagnostic_screener_d3_pattern_recognition_1768544121811_inj6b3', 'A', true, 5585, 3, 'pattern_recognition', 'diagnostic_screener', 6, '2026-01-26 05:04:24.924723+00', 'Ananya has a sequence of numbers: 2, 4, 8, 16. What is the next number in the pattern?', '{"A": "32", "B": "24", "C": "30", "D": "28"}', 'A', 'The pattern doubles each time: 16 × 2 = 32.'),
	('fe27a1ab-177a-42fb-bf2b-224226213b30', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d4_numerical_reasoning_1768549496456_dwnhqq', 'A', false, 25732, 4, 'numerical_reasoning', 'adaptive_core', 7, '2026-01-26 05:05:35.278558+00', 'Ananya has 80 marbles, and she wants to divide them equally among her 5 friends. After giving each friend an equal amount, she finds she has 10 marbles left. How many marbles did each friend receive?', '{"A": "14", "B": "16", "C": "18", "D": "20"}', 'B', 'If Ananya has 10 marbles left after giving away some, she must have given away 80 - 10 = 70 marbles. Dividing 70 by 5 friends means each friend gets 70 / 5 = 14 marbles.'),
	('bc15e202-0941-4f0a-aeac-0f563156695b', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d3_pattern_recognition_1769403938485_hu3tr2', 'C', true, 37593, 3, 'pattern_recognition', 'adaptive_core', 8, '2026-01-26 05:06:16.667357+00', 'Kavya is arranging her sticker collection. The first row has 3 stickers, the second has 6, the third has 9. If this pattern continues, how many stickers will be in the 6th row?', '{"A": "12", "B": "15", "C": "18", "D": "21"}', 'C', 'The pattern is adding 3 stickers each row. So the 4th row has 12, the 5th has 15, and the 6th has 18.'),
	('b7dfd887-6ee3-428d-8f06-588db7cb33c6', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d2_pattern_recognition_1768734956602_h3v6x9', 'C', true, 2496, 2, 'pattern_recognition', 'adaptive_core', 13, '2026-01-26 05:06:56.264318+00', 'Priya noticed a pattern in the number of stickers she collected each day: Monday: 5, Tuesday: 8, Wednesday: 11, Thursday: 14. How many stickers will she collect on Friday if the pattern continues?', '{"A": "15", "B": "16", "C": "17", "D": "18"}', 'C', 'The pattern adds 3 stickers each day (5→8→11→14). Following this, Friday''s count would be 14 + 3 = 17 stickers.'),
	('a15c2d14-602a-4241-8ba1-b1eb6b479363', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d4_spatial_reasoning_1769403982988_os5n07', 'C', true, 3757, 4, 'spatial_reasoning', 'adaptive_core', 9, '2026-01-26 05:06:27.42762+00', 'Priya is looking at a pattern of shapes. The first shape is a square. The second shape is a square rotated 90 degrees clockwise. The third shape is a square rotated 180 degrees clockwise. If this pattern continues, what will the fifth shape look like?', '{"A": "A square rotated 90 degrees clockwise", "B": "A square rotated 180 degrees clockwise", "C": "A square rotated 270 degrees clockwise", "D": "A square rotated 360 degrees clockwise (original position)"}', 'C', 'The pattern rotates the square by 90 degrees each step. Step 1: 0°, Step 2: 90°, Step 3: 180°, Step 4: 270°, Step 5: 360° which is equivalent to 270° clockwise from the original (since 360° brings it back to start).'),
	('cb5dcdb5-a3da-4bea-9723-4c24bbeb29ce', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d5_verbal_reasoning_1769403995049_0sskui', 'B', false, 3624, 5, 'verbal_reasoning', 'adaptive_core', 10, '2026-01-26 05:06:39.679305+00', 'Ananya is organizing a bookshelf. She has 3 mystery books, 5 science fiction books, and 4 history books. She decides to arrange them so that no two books of the same genre are next to each other. She also wants the first and last books to be of different genres. How many possible arrangements can she make if the books of the same genre are considered identical?', '{"A": "6", "B": "12", "C": "18", "D": "24"}', 'C', 'First, find the total number of arrangements without considering identical books: 12! / (3!5!4!) = 27,720. However, we must subtract arrangements where same-genre books are together. For the ''no two same-genre adjacent'' condition, we first place the 5 science fiction books (the largest group) as separators: _ S _ S _ S _ S _ S _. This creates 6 slots. We need to place 3 mystery and 4 history books into these slots, with at least 1 book in each of the 5 inner slots. After solving this constrained distribution and accounting for identical books within genres, the valid arrangements total 18.'),
	('e930a375-dc5f-41c6-8073-44ab915a50d4', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d4_logical_reasoning_1769404002634_6s2nzn', 'C', false, 3010, 4, 'logical_reasoning', 'adaptive_core', 11, '2026-01-26 05:06:46.959085+00', 'Aditya has a set of trading cards. He gives half of his cards to Sneha. Then, he gives 7 cards to Rohan. If Aditya now has 11 cards left, how many cards did he start with?', '{"A": "29", "B": "36", "C": "32", "D": "38"}', 'B', 'Aditya had 11 + 7 = 18 cards before giving cards to Rohan. Since this is half of his original amount, he started with 18 * 2 = 36 cards.'),
	('04949b3b-7c85-4f92-879d-7f82c55c3de9', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d3_spatial_reasoning_1768547464351_juek06', 'C', false, 2386, 3, 'spatial_reasoning', 'adaptive_core', 12, '2026-01-26 05:06:52.037245+00', 'Rohan has a rectangular garden that is 12 meters long and 8 meters wide. If he wants to increase the length by 25% and the width by 50%, what will be the new area of the garden in square meters?', '{"A": "120", "B": "144", "C": "180", "D": "192"}', 'D', 'New length = 12 + (25% of 12) = 12 + 3 = 15 meters. New width = 8 + (50% of 8) = 8 + 4 = 12 meters. Area = 15 * 12 = 180 square meters.'),
	('ca145bc2-26a7-4369-a333-dd9c7d3a54a8', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d3_verbal_reasoning_1768587516257_r38yc2', 'C', false, 2453, 3, 'verbal_reasoning', 'adaptive_core', 14, '2026-01-26 05:07:01.153412+00', 'If ''apple'' is to ''fruit'' as ''carrot'' is to what?', '{"A": "vegetable", "B": "color", "C": "root", "D": "orange"}', 'A', 'Apple is a type of fruit, just as carrot is a type of vegetable. The relationship is ''specific item to its category''.'),
	('ab9d4f1b-e6db-4677-91ac-e4059695b8aa', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d2_numerical_reasoning_1768539257820_r71jt2', 'C', false, 3611, 2, 'numerical_reasoning', 'adaptive_core', 15, '2026-01-26 05:07:06.207576+00', 'Priya has 150 stickers. She gives away 20% of them to her friends. How many stickers does she have left?', '{"A": "120", "B": "130", "C": "140", "D": "150"}', 'B', '20% of 150 is 30. So, 150 - 30 = 120 stickers left.'),
	('a00a6719-178f-40c7-bd48-6dce9e4ecedb', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d2_spatial_reasoning_1769235875627_haz8el', 'B', true, 2940, 2, 'spatial_reasoning', 'adaptive_core', 17, '2026-01-26 05:07:16.878151+00', 'Rohan has a square-shaped picture frame. If he rotates the frame 90 degrees clockwise, which of the following shows the correct new orientation?', '{"A": "The top side becomes the left side.", "B": "The top side becomes the right side.", "C": "The top side becomes the bottom side.", "D": "The top side stays on top."}', 'B', 'Rotating a square 90 degrees clockwise moves the top side to the right side, the right side to the bottom, the bottom to the left, and the left to the top.'),
	('5aa8d347-30d5-425b-9b9d-b1a394de38ab', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_stability_confirmation_d2_pattern_recognition_1768544792336_o6vwxw', 'B', false, 2959, 3, 'pattern_recognition', 'stability_confirmation', 18, '2026-01-26 05:07:26.69404+00', 'Sneha has 15 cards. If she buys 5 more and then gives 3 to her friend, how many cards does she have now?', '{"A": "17", "B": "18", "C": "16", "D": "15"}', 'A', 'First, add the new cards: 15 + 5 = 20. Then subtract the cards given away: 20 - 3 = 17.'),
	('79f20bfb-68dd-4438-90c8-26c469e2edbd', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_adaptive_core_d1_data_interpretation_1769756342897_fw26di', 'C', true, 1464, 1, 'data_interpretation', 'adaptive_core', 40, '2026-01-30 06:59:04.721854+00', 'A class of 25 students voted for their favorite fruit. 8 voted for apples, 7 voted for bananas, 6 voted for oranges, and the rest voted for grapes. How many students voted for grapes?', '{"A": "2", "B": "3", "C": "4", "D": "5"}', 'C', 'Total votes for apples, bananas, and oranges are 8 + 7 + 6 = 21. Since there are 25 students in total, 25 - 21 = 4 students voted for grapes.'),
	('2523cf93-c087-4576-ba98-b846b75d36be', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_diagnostic_d3_pattern_recognition_1769899538458_ve9u6k', 'B', false, 2639, 3, 'pattern_recognition', 'diagnostic_screener', 6, '2026-01-31 22:46:04.401088+00', 'Complete the series: 3, 6, 9, 12, 15, ...', '{"A": "16", "B": "17", "C": "18", "D": "19"}', 'C', 'Each number is increasing by 3, so the next number is 15 + 3 = 18.'),
	('756ebbad-289c-4996-8f4a-79ab066575b3', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d2_numerical_reasoning_1769899599900_4rdtg3', 'B', true, 1847, 2, 'numerical_reasoning', 'adaptive_core', 11, '2026-01-31 22:46:42.210924+00', 'If a box contains 24 apples, how many dozens of apples are in the box?', '{"A": "2", "B": "12", "C": "20", "D": "24"}', 'B', 'There are 12 apples in a dozen, so 24 apples equal 2 dozens.'),
	('755af023-1459-410c-8698-a83c0068a4e4', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_adaptive_core_d1_data_interpretation_1769236164916_mexx75', 'B', true, 3684, 1, 'data_interpretation', 'adaptive_core', 16, '2026-01-26 05:07:12.088412+00', 'Priya made a bar chart showing how many books she read each week. In Week 1 she read 4 books, Week 2 she read 6 books, and Week 3 she read 5 books. How many books did she read in total over the 3 weeks?', '{"A": "12 books", "B": "15 books", "C": "18 books", "D": "20 books"}', 'B', 'Add the books from each week: 4 + 6 + 5 = 15 books total.'),
	('33ddbbdd-b110-42bf-ac71-8e49562bef34', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_stability_d1_numerical_reasoning_1769756374487_y2t641', 'C', false, 2928, 1, 'numerical_reasoning', 'stability_confirmation', 45, '2026-01-30 06:59:37.746977+00', 'A pack of trading cards costs $2. If Leo buys 4 packs, how much does he spend in total?', '{"A": "$6", "B": "$8", "C": "$10", "D": "$12"}', 'B', 'Each pack costs $2, and Leo buys 4 packs, so he spends 4 * $2 = $8.'),
	('650aa708-3775-41a8-bce2-5e2ce9bb4bf6', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_diagnostic_d3_numerical_reasoning_1769899538458_7ihf2e', 'C', false, 6396, 3, 'numerical_reasoning', 'diagnostic_screener', 7, '2026-01-31 22:46:11.9664+00', 'If A = 1, B = 2, C = 3, what is the value of CAB?', '{"A": "6", "B": "24", "C": "321", "D": "123"}', 'D', 'CAB represents concatenation, so CAB = 321.'),
	('816d225a-12ac-4d1a-988b-4ab10e1fd9cf', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_stability_confirmation_d1_verbal_reasoning_1768539422983_4q664y', 'B', true, 2225, 3, 'verbal_reasoning', 'stability_confirmation', 19, '2026-01-26 05:07:29.980352+00', 'Kavya has 10 stickers and gives away 2. How many stickers does she have left?', '{"A": "6", "B": "8", "C": "10", "D": "12"}', 'B', 'Kavya started with 10 stickers and gave away 2. 10 - 2 = 8.'),
	('676dc585-a3e3-47fa-9bf2-7b634daaed4c', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_stability_confirmation_d3_pattern_recognition_1768623837167_lbsb5z', 'B', true, 2493, 3, 'pattern_recognition', 'stability_confirmation', 20, '2026-01-26 05:07:33.366138+00', 'Rohan has a collection of 120 stamps. He gives 1/4 of them to his sister and then buys 30 more. How many stamps does he have now?', '{"A": "105", "B": "120", "C": "135", "D": "150"}', 'B', 'First, he gives away 1/4 of 120, which is 30 stamps. He has 90 left. Then he buys 30 more, so 90 + 30 = 120.'),
	('4c153eef-e91e-4a5b-9eb2-ebcce21d1814', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_stability_d1_logical_reasoning_1769756374487_no0k62', 'C', false, 4055, 1, 'logical_reasoning', 'stability_confirmation', 46, '2026-01-30 06:59:42.439693+00', 'If it rains, the grass gets wet. The grass is not wet. What can you conclude?', '{"A": "It rained.", "B": "It did not rain.", "C": "The grass is always wet.", "D": "The grass was watered."}', 'B', 'Since the grass is not wet, the condition (rain) that causes it to get wet must not have occurred.'),
	('8ec3beb8-ef29-4339-8cd9-d41ed00b8f91', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_stability_d1_data_interpretation_1769756374487_y4uyoz', 'B', false, 1699, 1, 'data_interpretation', 'stability_confirmation', 49, '2026-01-30 06:59:53.341223+00', 'The following table shows the number of sunny days in a week. How many sunny days were there in total? 

Monday: 1
Tuesday: 0
Wednesday: 1
Thursday: 1
Friday: 1
Saturday: 1
Sunday: 0', '{"A": "3", "B": "4", "C": "5", "D": "6"}', 'C', 'Adding the number of sunny days for each day of the week: 1 + 0 + 1 + 1 + 1 + 1 + 0 = 5 sunny days.'),
	('f4fbcff8-3b56-4841-a05f-f2ea9ab34c16', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_diagnostic_d3_logical_reasoning_1769899538458_neqdwm', 'C', false, 2959, 3, 'logical_reasoning', 'diagnostic_screener', 8, '2026-01-31 22:46:15.971736+00', 'If 30% of a number is 45, what is 20% of that number?', '{"A": "30", "B": "33", "C": "36", "D": "39"}', 'B', 'If 30% = 45, then 1% = 45/30 = 1.5. Therefore, 20% = 1.5 * 20 = 30.'),
	('3b22a241-6e8a-42a5-aee4-5c67e1644b6d', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d3_logical_reasoning_1769899605105_5n49iv', 'A', false, 4409, 3, 'logical_reasoning', 'adaptive_core', 12, '2026-01-31 22:46:49.966699+00', 'If all sprockets are widgets, and some widgets are gadgets, then...', '{"A": "All sprockets are gadgets", "B": "Some sprockets are gadgets", "C": "All gadgets are sprockets", "D": "Some gadgets are sprockets"}', 'B', 'From the premise, it can be inferred that at least some sprockets are gadgets.'),
	('53e3c5c7-fe82-4900-9f2b-29524b08ccdf', 'a0e9d740-a39e-4232-945b-ef1679e02cb5', 'middle_school_stability_confirmation_d1_spatial_reasoning_1769404042730_48fguj', 'C', true, 2229, 3, 'spatial_reasoning', 'stability_confirmation', 21, '2026-01-26 05:07:36.439984+00', 'Priya drew a square on a piece of paper. If she rotates the square 90 degrees clockwise, which of the following shapes will it look the same as?', '{"A": "A triangle", "B": "A circle", "C": "A square", "D": "A rectangle"}', 'C', 'A square is a shape that looks the same even after a 90-degree rotation. The other shapes would look different.'),
	('2cb612c3-d308-477f-9c39-ea6b70761db8', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_diagnostic_screener_d3_numerical_reasoning_1768544632477_hl304n', 'C', true, 5191, 3, 'numerical_reasoning', 'diagnostic_screener', 1, '2026-01-26 05:20:34.662708+00', 'If Priya scored 80% on her math test and the test had 50 questions, how many questions did she answer correctly?', '{"A": "30", "B": "35", "C": "40", "D": "45"}', 'C', 'To find the number of correct answers: 80% of 50 is 0.8 * 50 = 40.'),
	('13bbfe6d-fd3e-4f0c-a59e-a014c740d430', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_diagnostic_screener_d3_logical_reasoning_1768544121811_q9rv8o', 'A', true, 6166, 3, 'logical_reasoning', 'diagnostic_screener', 2, '2026-01-26 05:20:42.212604+00', 'Rohan has 60 marbles. If 25% of them are blue, how many blue marbles does he have?', '{"A": "15", "B": "10", "C": "20", "D": "25"}', 'A', '25% of 60 = 0.25 × 60 = 15 blue marbles.'),
	('5c0ef65d-0403-4473-8a6c-1b51b3daa333', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_diagnostic_screener_d3_spatial_reasoning_1768539208241_8xffoa', 'B', false, 13264, 3, 'spatial_reasoning', 'diagnostic_screener', 3, '2026-01-26 05:20:56.489842+00', 'Rohan has a rectangular garden that is 10 meters long and 5 meters wide. What is the area of the garden?', '{"A": "15 square meters", "B": "25 square meters", "C": "50 square meters", "D": "75 square meters"}', 'C', 'The area is calculated by multiplying length and width: 10 m x 5 m = 50 square meters.'),
	('8e64d1d9-a31c-48b9-a6aa-6071e33fb81c', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_diagnostic_screener_d3_data_interpretation_1769235679023_rsj26y', 'C', true, 18377, 3, 'data_interpretation', 'diagnostic_screener', 4, '2026-01-26 05:21:15.429378+00', 'Rohan collected data on the types of fruit his friends brought for lunch. The table shows the results: Apples: 8, Oranges: 5, Bananas: 7, Grapes: 4. What is the total number of fruits brought by his friends?', '{"A": "20", "B": "22", "C": "24", "D": "26"}', 'C', 'Add all the numbers: 8 + 5 + 7 + 4 = 24 fruits in total.'),
	('4b17f6f6-68db-42f2-859d-794bea09c071', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_diagnostic_screener_d3_verbal_reasoning_1769235679023_5yzton', 'C', true, 2363, 3, 'verbal_reasoning', 'diagnostic_screener', 5, '2026-01-26 05:21:18.790499+00', 'Priya needs to find a word that has the same relationship as ''happy'' is to ''joyful''. Which word completes the analogy: ''sad'' is to ______?', '{"A": "happy", "B": "angry", "C": "unhappy", "D": "cheerful"}', 'C', 'The relationship is that ''joyful'' is a synonym for ''happy''. Similarly, ''unhappy'' is a synonym for ''sad''.'),
	('0aa8a287-001f-4989-849a-cc4174430c35', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_diagnostic_screener_d3_pattern_recognition_1768544121811_inj6b3', 'C', false, 2215, 3, 'pattern_recognition', 'diagnostic_screener', 6, '2026-01-26 05:21:21.463719+00', 'Ananya has a sequence of numbers: 2, 4, 8, 16. What is the next number in the pattern?', '{"A": "32", "B": "24", "C": "30", "D": "28"}', 'A', 'The pattern doubles each time: 16 × 2 = 32.'),
	('6bd1e524-4e6f-4f46-b2b5-e75184ad4fe1', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d3_logical_reasoning_1768883305913_birgrt', 'B', true, 2249, 3, 'logical_reasoning', 'adaptive_core', 7, '2026-01-26 05:21:26.996995+00', 'Rohan has 120 marbles. He gives 1/4 of them to his sister and then loses 1/3 of the remaining marbles. How many marbles does Rohan have left?', '{"A": "50", "B": "60", "C": "70", "D": "80"}', 'B', 'First, Rohan gives away 1/4 of 120, which is 30 marbles, leaving 90. Then he loses 1/3 of the remaining 90, which is 30 marbles. So, 90 - 30 = 60 marbles left.'),
	('5db03fb4-8fa6-4656-bbaf-ccaec3ad6304', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d4_logical_reasoning_1769404002634_6s2nzn', 'C', false, 2371, 4, 'logical_reasoning', 'adaptive_core', 8, '2026-01-26 05:21:31.150253+00', 'Aditya has a set of trading cards. He gives half of his cards to Sneha. Then, he gives 7 cards to Rohan. If Aditya now has 11 cards left, how many cards did he start with?', '{"A": "29", "B": "36", "C": "32", "D": "38"}', 'B', 'Aditya had 11 + 7 = 18 cards before giving cards to Rohan. Since this is half of his original amount, he started with 18 * 2 = 36 cards.'),
	('850661a7-e5fb-42d1-94ad-da71340664c0', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d3_pattern_recognition_1769403938485_hu3tr2', 'D', false, 4389, 3, 'pattern_recognition', 'adaptive_core', 9, '2026-01-26 05:21:37.641088+00', 'Kavya is arranging her sticker collection. The first row has 3 stickers, the second has 6, the third has 9. If this pattern continues, how many stickers will be in the 6th row?', '{"A": "12", "B": "15", "C": "18", "D": "21"}', 'C', 'The pattern is adding 3 stickers each row. So the 4th row has 12, the 5th has 15, and the 6th has 18.'),
	('10ccdb01-5b87-4ff7-b58a-0faac888f732', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d2_verbal_reasoning_1768539321051_i5gnfm', 'C', false, 2045, 2, 'verbal_reasoning', 'adaptive_core', 10, '2026-01-26 05:21:41.230803+00', 'Rohan is reading a book about animals. If he has read 30 pages and the book has a total of 120 pages, what fraction of the book has he completed?', '{"A": "1/4", "B": "1/3", "C": "1/2", "D": "1/5"}', 'B', 'Rohan has read 30 pages out of 120 pages. The fraction is 30/120, which simplifies to 1/4. Therefore, he has completed 1/4 of the book.'),
	('c974b1cd-0bf9-423f-9adb-64498f66c334', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d1_spatial_reasoning_1769236243220_bitarc', 'C', false, 2345, 1, 'spatial_reasoning', 'adaptive_core', 11, '2026-01-26 05:21:45.83883+00', 'Priya has a square piece of paper. She folds it in half once to make a rectangle, then folds that rectangle in half again. What is the final shape?', '{"A": "A square", "B": "A rectangle", "C": "A triangle", "D": "A circle"}', 'B', 'Folding a square in half once makes a rectangle. Folding that rectangle in half again still results in a rectangle, just smaller.'),
	('25145123-460b-460e-8ae8-2bee3e14ff8f', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d1_logical_reasoning_1769235865488_4kb0b8', 'C', true, 2399, 1, 'logical_reasoning', 'adaptive_core', 12, '2026-01-26 05:21:50.394218+00', 'Rohan is taller than Priya. Priya is taller than Ananya. Who is the tallest among the three?', '{"A": "Priya", "B": "Ananya", "C": "Rohan", "D": "They are all the same height"}', 'C', 'If Rohan is taller than Priya, and Priya is taller than Ananya, then Rohan must be the tallest.'),
	('9c291d81-472d-4bea-a44d-b69a868e12fc', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d2_spatial_reasoning_1768547932121_o3bn8j', 'B', true, 2558, 2, 'spatial_reasoning', 'adaptive_core', 13, '2026-01-26 05:21:55.061548+00', 'Priya has a rectangular garden that is 8 meters long and 5 meters wide. If she wants to put a fence around it, how many meters of fencing does she need?', '{"A": "26", "B": "30", "C": "40", "D": "50"}', 'B', 'The perimeter of a rectangle is calculated as P = 2(length + width). So, P = 2(8 + 5) = 2(13) = 26 meters.'),
	('7ff9b74c-cc17-48c5-9403-03110596e3ca', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d3_verbal_reasoning_1768587516257_r38yc2', 'B', false, 3343, 3, 'verbal_reasoning', 'adaptive_core', 14, '2026-01-26 05:22:00.295832+00', 'If ''apple'' is to ''fruit'' as ''carrot'' is to what?', '{"A": "vegetable", "B": "color", "C": "root", "D": "orange"}', 'A', 'Apple is a type of fruit, just as carrot is a type of vegetable. The relationship is ''specific item to its category''.'),
	('0a1da749-3c61-4519-961e-4bf095b58f9c', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d2_numerical_reasoning_1769404926837_0jez79', 'B', false, 3045, 2, 'numerical_reasoning', 'adaptive_core', 15, '2026-01-26 05:22:10.503349+00', 'Priya collected 45 stickers. She gave 12 stickers to her friend and then bought 8 more stickers from the store. How many stickers does Priya have now?', '{"A": "41", "B": "45", "C": "49", "D": "53"}', 'A', 'Start with 45 stickers. Subtract 12 (45 - 12 = 33). Then add 8 (33 + 8 = 41). Priya has 41 stickers.'),
	('7000a439-4ca5-4809-ae5f-07c218ed5689', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d1_verbal_reasoning_1769236139018_276a5o', 'B', false, 2525, 1, 'verbal_reasoning', 'adaptive_core', 16, '2026-01-26 05:22:14.39952+00', 'Rohan has 8 marbles. He gives 3 marbles to his friend Priya. How many marbles does Rohan have left?', '{"A": "5", "B": "11", "C": "3", "D": "8"}', 'A', 'Rohan started with 8 marbles and gave away 3, so 8 - 3 = 5 marbles remain.'),
	('a5fd986b-1177-4124-8631-f7802bf69a7a', '898b6585-6a7a-4a3e-95f7-efa2dd641a82', 'higher_secondary_adaptive_core_d1_pattern_recognition_1769492147252_6ceeoi', 'B', true, 3353, 1, 'pattern_recognition', 'adaptive_core', 34, '2026-01-27 05:35:51.41493+00', 'Complete the pattern: A, C, E, G, ?', '{"A": "H", "B": "I", "C": "J", "D": "K"}', 'B', 'Fallback question'),
	('21c28869-8564-46b6-aa61-191750342f21', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_adaptive_core_d1_logical_reasoning_1769236268330_l88iic', 'B', false, 2117, 1, 'logical_reasoning', 'adaptive_core', 17, '2026-01-26 05:22:18.147744+00', 'Priya has 8 red marbles and 5 blue marbles. She gives 3 marbles to her friend. How many marbles does Priya have left?', '{"A": "10", "B": "13", "C": "11", "D": "15"}', 'A', 'Priya starts with 8 + 5 = 13 marbles. After giving away 3, she has 13 - 3 = 10 marbles left.'),
	('4a38d1ba-7287-40fe-ae2f-1dc981af7c1a', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_stability_confirmation_d1_data_interpretation_1768544251751_z1oijc', 'C', false, 2253, 1, 'data_interpretation', 'stability_confirmation', 18, '2026-01-26 05:22:26.118276+00', 'Rohan collected 12 stickers and then received 7 more from his friend. How many stickers does he have now?', '{"A": "19 stickers", "B": "20 stickers", "C": "18 stickers", "D": "21 stickers"}', 'A', 'To find the total number of stickers, add the stickers Rohan collected (12) to the ones he received (7): 12 + 7 = 19 stickers.'),
	('b022d1f1-11f2-4bfc-8f63-e1bb9f4a47be', 'd25e061d-4948-4d21-897e-df97a39815ca', 'middle_school_stability_d1_verbal_reasoning_1769756374487_xiyrea', 'B', true, 4395, 1, 'verbal_reasoning', 'stability_confirmation', 47, '2026-01-30 06:59:47.45469+00', 'Choose the word that best completes the following analogy: Up is to down as big is to:', '{"A": "Tall", "B": "Small", "C": "Large", "D": "Wide"}', 'B', 'Up and down are opposites, and big and small are opposites.'),
	('51062622-867e-4ef1-92ef-ea8173292897', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d3_verbal_reasoning_1769899592262_ibbrjd', 'D', false, 4555, 3, 'verbal_reasoning', 'adaptive_core', 10, '2026-01-31 22:46:37.276031+00', 'What is the synonym of ''pinnacle''?', '{"A": "Peak", "B": "Valley", "C": "Plateau", "D": "Canyon"}', 'A', '''Pinnacle'' means the highest point, synonymous with ''Peak''.'),
	('56e3c7b8-e98e-45bb-b224-a8cbd9f46e8a', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_stability_confirmation_d1_spatial_reasoning_1769404042730_48fguj', 'B', false, 2071, 1, 'spatial_reasoning', 'stability_confirmation', 19, '2026-01-26 05:22:28.636037+00', 'Priya drew a square on a piece of paper. If she rotates the square 90 degrees clockwise, which of the following shapes will it look the same as?', '{"A": "A triangle", "B": "A circle", "C": "A square", "D": "A rectangle"}', 'C', 'A square is a shape that looks the same even after a 90-degree rotation. The other shapes would look different.'),
	('a53c3ffe-bd58-4966-b3cc-9226f67b16af', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_diagnostic_d3_numerical_reasoning_1769758253076_49lw23', 'B', false, 16205, 3, 'numerical_reasoning', 'diagnostic_screener', 1, '2026-01-30 07:31:09.769008+00', 'A baker makes 24 cookies in one hour. If he needs to bake 120 cookies for a school event, how many hours will it take him?', '{"A": "3 hours", "B": "4 hours", "C": "5 hours", "D": "6 hours"}', 'C', 'Divide the total cookies needed (120) by the number of cookies baked per hour (24): 120 / 24 = 5 hours.'),
	('08f0ff0d-02d5-413c-b8b2-06835a310152', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_diagnostic_d3_logical_reasoning_1769758253079_s9zzzf', 'C', true, 1222, 3, 'logical_reasoning', 'diagnostic_screener', 2, '2026-01-30 07:31:11.974478+00', 'All cats like fish. Mittens is a cat. Therefore, Mittens likes:', '{"A": "Birds", "B": "Milk", "C": "Fish", "D": "Yarn"}', 'C', 'The logic states that if all cats like fish, and Mittens is a cat, then Mittens must like fish.'),
	('c9354254-bbd1-4042-896b-81b4e2756c92', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_diagnostic_d3_data_interpretation_1769758253079_06fp9n', 'A', false, 1357, 3, 'data_interpretation', 'diagnostic_screener', 5, '2026-01-30 07:31:18.245409+00', 'The following chart shows the number of students who like different sports: Football (15), Basketball (20), Soccer (25), and Volleyball (10). Which sport is liked by the most students?', '{"A": "Football", "B": "Basketball", "C": "Soccer", "D": "Volleyball"}', 'C', 'The chart shows that Soccer is liked by 25 students, which is the highest number among the sports listed.'),
	('3b5810e5-ea21-4d6d-9505-81e5e96976f3', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d5_logical_reasoning_1769758469761_u9moed', 'A', false, 11168, 5, 'logical_reasoning', 'adaptive_core', 27, '2026-01-30 07:34:42.144183+00', 'Four friends – Emily, David, Sarah, and Chris – each collect a different type of item: stamps, coins, rocks, or shells. Emily doesn''t collect coins or shells. David collects rocks. Chris doesn''t collect stamps. Sarah doesn''t collect shells. Who collects which item?', '{"A": "Emily: Stamps, David: Rocks, Sarah: Coins, Chris: Shells", "B": "Emily: Rocks, David: Stamps, Sarah: Shells, Chris: Coins", "C": "Emily: Stamps, David: Rocks, Sarah: Shells, Chris: Coins", "D": "Emily: Coins, David: Rocks, Sarah: Stamps, Chris: Shells"}', 'C', 'David collects rocks. Emily doesn''t collect coins or shells, so she must collect stamps. Chris doesn''t collect stamps, and Sarah doesn''t collect shells, so Chris must collect coins, leaving shells for Sarah.'),
	('a2ed3218-d1e6-4cd5-9872-0b5a45b3ab6e', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d2_data_interpretation_1769899612826_3jtsdt', 'A', true, 2583, 2, 'data_interpretation', 'adaptive_core', 13, '2026-01-31 22:46:55.899901+00', 'In a survey, 60% of people preferred apples and 30% preferred bananas. If 100 people were surveyed, how many preferred bananas?', '{"A": "20", "B": "30", "C": "40", "D": "50"}', 'A', 'Out of 100 people, 30% preferred bananas, which is 30 people.'),
	('0790d038-1557-44db-9e74-a166b9338685', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_stability_confirmation_d2_pattern_recognition_1768544792336_o6vwxw', 'B', false, 1982, 1, 'pattern_recognition', 'stability_confirmation', 20, '2026-01-26 05:22:31.197653+00', 'Sneha has 15 cards. If she buys 5 more and then gives 3 to her friend, how many cards does she have now?', '{"A": "17", "B": "18", "C": "16", "D": "15"}', 'A', 'First, add the new cards: 15 + 5 = 20. Then subtract the cards given away: 20 - 3 = 17.'),
	('65fdbcbb-5bc9-4179-87b9-3d930996089f', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_diagnostic_d3_verbal_reasoning_1769758253079_v8bfgc', 'B', true, 1401, 3, 'verbal_reasoning', 'diagnostic_screener', 3, '2026-01-30 07:31:14.042934+00', 'Choose the word that best completes the following analogy: Happy is to Sad as Fast is to:', '{"A": "Quick", "B": "Slow", "C": "Rabbit", "D": "Road"}', 'B', 'Happy and Sad are antonyms (opposites). Fast and Slow are also antonyms.'),
	('9b8c5337-fc21-4ab3-a030-3b4435bf5f65', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d3_pattern_recognition_1769758355974_lmnquj', 'B', false, 8827, 3, 'pattern_recognition', 'adaptive_core', 16, '2026-01-30 07:32:45.222432+00', 'Look at this pattern: Triangle, Square, Pentagon, Hexagon, ____. What shape comes next?', '{"A": "Heptagon", "B": "Octagon", "C": "Nonagon", "D": "Decagon"}', 'A', 'The pattern increases the number of sides of the polygon by one each time. A heptagon has seven sides.'),
	('a2a6bd88-30f6-495b-9f5f-0456d3d85344', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d1_logical_reasoning_1769758377188_z0i2qq', 'C', false, 17797, 1, 'logical_reasoning', 'adaptive_core', 18, '2026-01-30 07:33:15.380078+00', 'All students in the art club enjoy painting. Emily is in the art club. Which statement must be true?', '{"A": "Emily also likes to sing.", "B": "Emily enjoys painting.", "C": "Emily is the president of the art club.", "D": "Emily dislikes drawing."}', 'B', 'Since all art club members enjoy painting and Emily is in the art club, it must be true that Emily enjoys painting.'),
	('8574b22e-7f9b-41c2-b82e-bb314dfa6858', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d4_data_interpretation_1769758486917_7s5oi8', 'A', false, 3248, 4, 'data_interpretation', 'adaptive_core', 28, '2026-01-30 07:34:51.053891+00', 'A school club tracked the number of cans they recycled each month for four months. In January they recycled 75 cans, in February 90 cans, in March 120 cans, and in April 105 cans. Which statement is best supported by this data?', '{"A": "The club consistently increased the number of cans recycled each month.", "B": "The club recycled the most cans in February.", "C": "The club recycled fewer cans in April than in March.", "D": "The club will recycle more than 150 cans in May."}', 'C', 'The data shows that the club recycled 120 cans in March and only 105 cans in April, supporting the statement that they recycled fewer cans in April than in March. The other options are not directly supported by the data: the number of cans does not consistently increase (eliminating A), March had the most cans (eliminating B), and there is no information about May (eliminating D).'),
	('9b3d931b-d700-48e1-a2c0-55cdb90d9251', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d3_numerical_reasoning_1769899618295_y214pe', 'B', true, 51168, 3, 'numerical_reasoning', 'adaptive_core', 14, '2026-01-31 22:47:50.122292+00', 'If a car travels 180 miles in 3 hours, what is its average speed in miles per hour?', '{"A": "45", "B": "60", "C": "75", "D": "90"}', 'B', 'Average speed = Total distance / Total time = 180 miles / 3 hours = 60 mph'),
	('811fae55-0222-4f4b-a03e-b45c8b5affa9', 'e7febe8b-1aea-4af8-848b-1859d1ba9ba6', 'middle_school_stability_confirmation_d2_verbal_reasoning_1769404943578_86k93d', 'C', false, 2669, 1, 'verbal_reasoning', 'stability_confirmation', 21, '2026-01-26 05:22:34.873544+00', 'Priya notices that ''happy'' is to ''joyful'' as ''sad'' is to which word?', '{"A": "angry", "B": "gloomy", "C": "tired", "D": "excited"}', 'B', '''Happy'' and ''joyful'' are synonyms (words with similar meanings). ''Sad'' and ''gloomy'' are also synonyms.'),
	('f82d6fba-8962-4715-aaff-6965b1579c99', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_diagnostic_screener_d3_pattern_recognition_1768544121811_inj6b3', 'A', true, 4761, 3, 'pattern_recognition', 'diagnostic_screener', 1, '2026-01-26 05:32:59.63584+00', 'Ananya has a sequence of numbers: 2, 4, 8, 16. What is the next number in the pattern?', '{"A": "32", "B": "24", "C": "30", "D": "28"}', 'A', 'The pattern doubles each time: 16 × 2 = 32.'),
	('14f4f385-a659-479e-894d-4875915ba148', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_diagnostic_screener_d3_verbal_reasoning_1769235679023_5yzton', 'C', true, 3874, 3, 'verbal_reasoning', 'diagnostic_screener', 2, '2026-01-26 05:33:05.329856+00', 'Priya needs to find a word that has the same relationship as ''happy'' is to ''joyful''. Which word completes the analogy: ''sad'' is to ______?', '{"A": "happy", "B": "angry", "C": "unhappy", "D": "cheerful"}', 'C', 'The relationship is that ''joyful'' is a synonym for ''happy''. Similarly, ''unhappy'' is a synonym for ''sad''.'),
	('720964e3-d903-43c4-b0fc-a83e4fe99a55', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_diagnostic_screener_d3_logical_reasoning_1768544121811_q9rv8o', 'C', false, 3422, 3, 'logical_reasoning', 'diagnostic_screener', 3, '2026-01-26 05:33:09.984573+00', 'Rohan has 60 marbles. If 25% of them are blue, how many blue marbles does he have?', '{"A": "15", "B": "10", "C": "20", "D": "25"}', 'A', '25% of 60 = 0.25 × 60 = 15 blue marbles.'),
	('fc055ee3-4fca-40f2-8d4f-17f24e76dbf9', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_diagnostic_screener_d3_numerical_reasoning_1768544632477_hl304n', 'C', true, 2436, 3, 'numerical_reasoning', 'diagnostic_screener', 4, '2026-01-26 05:33:13.288665+00', 'If Priya scored 80% on her math test and the test had 50 questions, how many questions did she answer correctly?', '{"A": "30", "B": "35", "C": "40", "D": "45"}', 'C', 'To find the number of correct answers: 80% of 50 is 0.8 * 50 = 40.'),
	('86530c18-2959-4a64-9f05-33640fe55f46', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_diagnostic_screener_d3_data_interpretation_1769235679023_rsj26y', 'B', false, 8931, 3, 'data_interpretation', 'diagnostic_screener', 5, '2026-01-26 05:33:22.958805+00', 'Rohan collected data on the types of fruit his friends brought for lunch. The table shows the results: Apples: 8, Oranges: 5, Bananas: 7, Grapes: 4. What is the total number of fruits brought by his friends?', '{"A": "20", "B": "22", "C": "24", "D": "26"}', 'C', 'Add all the numbers: 8 + 5 + 7 + 4 = 24 fruits in total.'),
	('f9778d18-a7cb-43cc-9960-23ac05961d83', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_diagnostic_screener_d3_spatial_reasoning_1768539208241_8xffoa', 'D', false, 3192, 3, 'spatial_reasoning', 'diagnostic_screener', 6, '2026-01-26 05:33:26.906247+00', 'Rohan has a rectangular garden that is 10 meters long and 5 meters wide. What is the area of the garden?', '{"A": "15 square meters", "B": "25 square meters", "C": "50 square meters", "D": "75 square meters"}', 'C', 'The area is calculated by multiplying length and width: 10 m x 5 m = 50 square meters.'),
	('36a62c0c-5500-4ace-ba38-41d9c89f6b95', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d3_spatial_reasoning_1768547464351_juek06', 'B', false, 3427, 3, 'spatial_reasoning', 'adaptive_core', 7, '2026-01-26 05:34:15.957418+00', 'Rohan has a rectangular garden that is 12 meters long and 8 meters wide. If he wants to increase the length by 25% and the width by 50%, what will be the new area of the garden in square meters?', '{"A": "120", "B": "144", "C": "180", "D": "192"}', 'D', 'New length = 12 + (25% of 12) = 12 + 3 = 15 meters. New width = 8 + (50% of 8) = 8 + 4 = 12 meters. Area = 15 * 12 = 180 square meters.'),
	('8d3ee807-8c62-41f5-9cc9-4f2d144008e1', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d2_logical_reasoning_1769235976024_kk5tyj', 'D', false, 2542, 2, 'logical_reasoning', 'adaptive_core', 8, '2026-01-26 05:34:20.590304+00', 'Priya has 15 red marbles and 10 blue marbles. She gives 5 red marbles to her friend. How many more red marbles than blue marbles does she have now?', '{"A": "5", "B": "10", "C": "15", "D": "20"}', 'A', 'Priya has 15 - 5 = 10 red marbles left. She has 10 blue marbles. The difference is 10 - 10 = 0, but the question asks for ''more red than blue''. Since she has equal numbers, she has 0 more red marbles, but 5 is the correct answer because 10 red - 5 given = 5 remaining red, and 5 - 10 blue = -5, meaning 5 fewer red. The difference is 5 (10 red - 5 blue = 5).'),
	('a86e2b1a-671b-42d5-82ea-3eb197d2da6d', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d1_spatial_reasoning_1769236243220_bitarc', 'C', false, 2318, 1, 'spatial_reasoning', 'adaptive_core', 9, '2026-01-26 05:34:24.599967+00', 'Priya has a square piece of paper. She folds it in half once to make a rectangle, then folds that rectangle in half again. What is the final shape?', '{"A": "A square", "B": "A rectangle", "C": "A triangle", "D": "A circle"}', 'B', 'Folding a square in half once makes a rectangle. Folding that rectangle in half again still results in a rectangle, just smaller.'),
	('9419c397-c027-40d7-9f8f-cbc7faddd33e', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d1_data_interpretation_1769236164916_mexx75', 'C', false, 2806, 1, 'data_interpretation', 'adaptive_core', 10, '2026-01-26 05:34:29.025758+00', 'Priya made a bar chart showing how many books she read each week. In Week 1 she read 4 books, Week 2 she read 6 books, and Week 3 she read 5 books. How many books did she read in total over the 3 weeks?', '{"A": "12 books", "B": "15 books", "C": "18 books", "D": "20 books"}', 'B', 'Add the books from each week: 4 + 6 + 5 = 15 books total.'),
	('2e9bb5dd-6603-43d9-bce0-e64042fb1f43', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d1_logical_reasoning_1769235865488_4kb0b8', 'C', true, 5940, 1, 'logical_reasoning', 'adaptive_core', 11, '2026-01-26 05:34:36.847724+00', 'Rohan is taller than Priya. Priya is taller than Ananya. Who is the tallest among the three?', '{"A": "Priya", "B": "Ananya", "C": "Rohan", "D": "They are all the same height"}', 'C', 'If Rohan is taller than Priya, and Priya is taller than Ananya, then Rohan must be the tallest.'),
	('b6089cec-ed2d-4070-8c31-9cbb2970bf08', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d2_verbal_reasoning_1768801609341_3irsuw', 'C', true, 4759, 2, 'verbal_reasoning', 'adaptive_core', 12, '2026-01-26 05:34:43.425982+00', 'Priya has 5 notebooks. She buys 3 more and then gives 2 to her friend. How many notebooks does she have now?', '{"A": "4", "B": "5", "C": "6", "D": "7"}', 'C', 'Start with 5 notebooks. Add 3: 5 + 3 = 8. Subtract 2: 8 - 2 = 6. So Priya has 6 notebooks.'),
	('7dae0a87-8f5f-466c-a508-47b21ff622ee', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d3_data_interpretation_1769235961163_phtvjy', 'B', true, 2890, 3, 'data_interpretation', 'adaptive_core', 13, '2026-01-26 05:34:47.898418+00', 'Priya tracked her reading over a week. The bar graph shows: Monday: 25 pages, Tuesday: 30 pages, Wednesday: 20 pages, Thursday: 35 pages, Friday: 15 pages. What was the average number of pages Priya read per day?', '{"A": "20 pages", "B": "25 pages", "C": "28 pages", "D": "30 pages"}', 'B', 'Add the pages: 25+30+20+35+15 = 125 pages. Divide by 5 days: 125 ÷ 5 = 25 pages per day.'),
	('000a1e84-9a0e-4ee3-8920-55450afb6a8b', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d4_spatial_reasoning_1769403982988_os5n07', 'D', false, 4077, 4, 'spatial_reasoning', 'adaptive_core', 14, '2026-01-26 05:34:54.300455+00', 'Priya is looking at a pattern of shapes. The first shape is a square. The second shape is a square rotated 90 degrees clockwise. The third shape is a square rotated 180 degrees clockwise. If this pattern continues, what will the fifth shape look like?', '{"A": "A square rotated 90 degrees clockwise", "B": "A square rotated 180 degrees clockwise", "C": "A square rotated 270 degrees clockwise", "D": "A square rotated 360 degrees clockwise (original position)"}', 'C', 'The pattern rotates the square by 90 degrees each step. Step 1: 0°, Step 2: 90°, Step 3: 180°, Step 4: 270°, Step 5: 360° which is equivalent to 270° clockwise from the original (since 360° brings it back to start).'),
	('d7c87856-330b-4f56-bec0-eafb6bade160', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d3_verbal_reasoning_1768587516257_r38yc2', 'B', false, 3655, 3, 'verbal_reasoning', 'adaptive_core', 15, '2026-01-26 05:34:59.503836+00', 'If ''apple'' is to ''fruit'' as ''carrot'' is to what?', '{"A": "vegetable", "B": "color", "C": "root", "D": "orange"}', 'A', 'Apple is a type of fruit, just as carrot is a type of vegetable. The relationship is ''specific item to its category''.'),
	('6aa1e9dd-039f-46bd-ae28-f18a7375872b', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d2_logical_reasoning_1769236063297_9claay', 'B', true, 2692, 2, 'logical_reasoning', 'adaptive_core', 16, '2026-01-26 05:35:04.270368+00', 'Rohan has 15 red marbles and 8 blue marbles. He gives 5 red marbles and 3 blue marbles to Priya. How many more red marbles than blue marbles does Rohan have now?', '{"A": "3", "B": "4", "C": "5", "D": "6"}', 'B', 'Rohan has 15-5=10 red marbles and 8-3=5 blue marbles. 10-5=5 more red marbles, but wait... 10-5=5. Let me recalculate: 10 red, 5 blue, so 10-5=5. But option B is 4. Let me check the numbers again. Actually, 15-5=10 red, 8-3=5 blue, so 10-5=5. Hmm, that gives 5. Let me think... maybe I made an error. Wait, the question asks ''how many more red marbles than blue marbles'' - that''s red minus blue: 10-5=5. But 5 is option C. Let me re-read... Oh! I see the issue. The numbers: 15 red, 8 blue. Give 5 red, 3 blue. Remaining: red = 15-5=10, blue = 8-3=5. Difference = 10-5=5. So answer should be C, not B. But I need to verify the calculation once more to be absolutely certain. Yes, 10 minus 5 equals 5. So the correct answer is C: 5.'),
	('445e2d87-5d73-4a39-9fcf-909a171d6daf', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_adaptive_core_d3_pattern_recognition_1769403938485_hu3tr2', 'C', true, 3510, 3, 'pattern_recognition', 'adaptive_core', 17, '2026-01-26 05:35:10.219792+00', 'Kavya is arranging her sticker collection. The first row has 3 stickers, the second has 6, the third has 9. If this pattern continues, how many stickers will be in the 6th row?', '{"A": "12", "B": "15", "C": "18", "D": "21"}', 'C', 'The pattern is adding 3 stickers each row. So the 4th row has 12, the 5th has 15, and the 6th has 18.'),
	('50accafe-a066-4073-aa21-5376004a18a2', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_stability_confirmation_d3_data_interpretation_1768564496218_z2kshd', 'C', false, 2478, 4, 'data_interpretation', 'stability_confirmation', 18, '2026-01-26 05:35:23.190502+00', 'Priya collected data on the number of books read by her 5 friends over summer vacation. The data is: 8, 12, 15, 8, 17. What is the median number of books read?', '{"A": "8", "B": "12", "C": "15", "D": "17"}', 'B', 'First, arrange the numbers in order: 8, 8, 12, 15, 17. The median is the middle value, which is 12.'),
	('73488b65-f402-46d5-a0fe-c97881622df9', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_stability_confirmation_d2_verbal_reasoning_1769404943578_86k93d', 'C', false, 3326, 4, 'verbal_reasoning', 'stability_confirmation', 19, '2026-01-26 05:35:28.265742+00', 'Priya notices that ''happy'' is to ''joyful'' as ''sad'' is to which word?', '{"A": "angry", "B": "gloomy", "C": "tired", "D": "excited"}', 'B', '''Happy'' and ''joyful'' are synonyms (words with similar meanings). ''Sad'' and ''gloomy'' are also synonyms.'),
	('8e0fe534-6cd9-4ad2-9b52-8cafa9056744', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_stability_confirmation_d4_pattern_recognition_1769405720154_tii6pp', 'C', false, 3375, 4, 'pattern_recognition', 'stability_confirmation', 20, '2026-01-26 05:35:33.843941+00', 'Aarav notices a pattern in his stamp collection: 2 stamps, 5 stamps, 10 stamps, 17 stamps, 26 stamps. If this pattern continues, how many stamps would be in the next group?', '{"A": "35 stamps", "B": "37 stamps", "C": "39 stamps", "D": "41 stamps"}', 'B', 'The pattern adds consecutive odd numbers: 2+3=5, 5+5=10, 10+7=17, 17+9=26. The next odd number is 11, so 26+11=37.'),
	('49bdea09-f902-4460-b9e8-e121e2fc5e2f', '66e3c4cc-19ae-40bf-b69e-96d87b4451eb', 'middle_school_stability_confirmation_d3_verbal_reasoning_1769405720154_snulkw', 'B', true, 4683, 4, 'verbal_reasoning', 'stability_confirmation', 21, '2026-01-26 05:35:39.765664+00', 'Priya''s teacher gave her a riddle: ''I am a word that means ''opposite of short'' and also describes a tall plant that grows in the garden.'' What word is this?', '{"A": "Fast", "B": "Tall", "C": "Wide", "D": "Heavy"}', 'B', 'The word ''tall'' means the opposite of short and describes plants like sunflowers or trees that grow tall in gardens.'),
	('5b95bcb5-85ba-4431-8fb0-8b56807ee53d', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_diagnostic_screener_d3_numerical_reasoning_1769406410519_41ar0j', 'C', true, 6217, 3, 'numerical_reasoning', 'diagnostic_screener', 1, '2026-01-26 05:47:01.178008+00', 'A car travels 240 miles in 4 hours. What is its average speed?', '{"A": "50 mph", "B": "55 mph", "C": "60 mph", "D": "65 mph"}', 'C', 'Fallback question'),
	('1fbaf36a-7a86-4e64-b5f8-20e3d974af07', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_diagnostic_screener_d3_data_interpretation_1768625276618_lmfwxk', 'B', false, 13608, 3, 'data_interpretation', 'diagnostic_screener', 2, '2026-01-26 05:47:21.133135+00', 'The table below shows the number of books Rohan read each month over a semester. If he read 15 books in total, what was the average number of books per month?

Month | Books Read
------|-----------
June  | 4
July  | 3
August| 5
September | ?', '{"A": "3", "B": "4", "C": "5", "D": "6"}', 'A', 'Total books read = 15. Books read in known months = 4 + 3 + 5 = 12. Books read in September = 15 - 12 = 3. The average over 4 months is 15/4 = 3.75, but the question asks for the number of books in September, which is 3.'),
	('4ef05ee6-c8ad-4b13-8c13-9744d3619285', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_diagnostic_screener_d3_logical_reasoning_1769406410519_2neuqu', 'B', true, 2777, 3, 'logical_reasoning', 'diagnostic_screener', 3, '2026-01-26 05:47:25.852373+00', 'All mammals are warm-blooded. Whales are mammals. Therefore:', '{"A": "Whales live in water", "B": "Whales are warm-blooded", "C": "All warm-blooded are mammals", "D": "Whales are fish"}', 'B', 'Fallback question'),
	('0ac8dd71-3736-412a-bd94-2df53d674e2b', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_diagnostic_screener_d3_verbal_reasoning_1768625276618_pmkatg', 'C', false, 2615, 3, 'verbal_reasoning', 'diagnostic_screener', 4, '2026-01-26 05:47:31.607252+00', 'Choose the word that best completes the analogy: Architect : Blueprint :: Surgeon : ?', '{"A": "Scalpel", "B": "Patient", "C": "Hospital", "D": "Anatomy"}', 'A', 'An architect uses a blueprint as a detailed plan for construction. A surgeon uses a scalpel as a primary tool for performing surgery. The relationship is ''professional : primary tool''.'),
	('f39b4d97-cb7d-4367-8106-05cf852333e5', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_diagnostic_screener_d3_pattern_recognition_1769406410519_f7qumd', 'C', false, 9035, 3, 'pattern_recognition', 'diagnostic_screener', 5, '2026-01-26 05:47:44.528788+00', 'Complete the pattern: A, C, E, G, ?', '{"A": "H", "B": "I", "C": "J", "D": "K"}', 'B', 'Fallback question'),
	('0402dd42-ff74-42e8-a5f4-b419cdfb4cf8', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_diagnostic_screener_d3_spatial_reasoning_1768625276618_d9qimt', 'C', false, 4294, 3, 'spatial_reasoning', 'diagnostic_screener', 6, '2026-01-26 05:47:52.285652+00', 'Vikram is looking at a 2D net of a 3D cube. When this net is folded, which of the following faces will be opposite the face marked with a star (★)?

[Imagine a net with 6 squares in a cross shape. The top square has a star. The square directly below it is the center of the cross. The square to the right of the center is marked with a circle (●). The square to the left of the center is marked with a triangle (▲). The square below the center is marked with a square (■). The square at the bottom is marked with a diamond (♦).]', '{"A": "The circle (●)", "B": "The triangle (▲)", "C": "The square (■)", "D": "The diamond (♦)"}', 'D', 'In a standard cross-shaped net of a cube, the top face is opposite the bottom face. The star (★) is on the top square. The diamond (♦) is on the bottom square. Therefore, when folded, the star will be opposite the diamond.'),
	('5c13fbe5-c976-4924-9a61-bca55568714d', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d2_spatial_reasoning_1768625391248_le7qmh', 'C', false, 3403, 2, 'spatial_reasoning', 'adaptive_core', 7, '2026-01-26 05:48:02.32364+00', 'A cube is painted red on all faces and then cut into 8 smaller cubes of equal size. How many smaller cubes have exactly two red faces?', '{"A": "0", "B": "4", "C": "6", "D": "8"}', 'B', 'When a cube is cut into 8 smaller cubes (2×2×2), the cubes with exactly two painted faces are the ones on the edges but not corners. There are 4 such cubes.'),
	('2e730d1b-3b4a-4a51-b6b9-8c15f4da8b43', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_logical_reasoning_1769406491771_ag03zt', 'C', false, 3733, 1, 'logical_reasoning', 'adaptive_core', 8, '2026-01-26 05:48:16.939233+00', 'Priya says: ''All dogs are mammals. My pet, Bruno, is a dog.'' What can be concluded about Bruno?', '{"A": "Bruno is not a mammal.", "B": "Bruno is a mammal.", "C": "Bruno is a cat.", "D": "All mammals are dogs."}', 'B', 'This is a basic syllogism. If all dogs are mammals and Bruno is a dog, then Bruno must be a mammal. The other options either contradict the premises or introduce unrelated information.'),
	('c65ea440-007b-4b57-8b39-d6573e42c347', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_verbal_reasoning_1768626328933_zvnm7j', 'A', false, 11976, 1, 'verbal_reasoning', 'adaptive_core', 9, '2026-01-26 05:48:31.419152+00', 'Complete the following analogy: Happy is to Joyful as Sad is to:', '{"A": "Content", "B": "Angry", "C": "Miserable", "D": "Excited"}', 'C', 'Happy and Joyful are synonyms, similarly Sad and Miserable are synonyms. The other options are not direct synonyms of ''sad''.'),
	('fdb17db7-5fdd-4590-8577-d4d9eb91af67', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_spatial_reasoning_1768625391248_vlimp9', 'B', false, 2917, 1, 'spatial_reasoning', 'adaptive_core', 11, '2026-01-26 05:48:47.871645+00', 'Which shape will complete the pattern? The sequence shows: Square, Circle, Triangle, Square, Circle, ________.', '{"A": "Square", "B": "Circle", "C": "Triangle", "D": "Rectangle"}', 'C', 'The pattern repeats every three shapes: Square, Circle, Triangle. The next shape should be Triangle.'),
	('45e6f3cd-ad58-41d1-aa85-ccf8659a6889', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_diagnostic_d3_spatial_reasoning_1769758253079_ksnou6', 'B', true, 1460, 3, 'spatial_reasoning', 'diagnostic_screener', 4, '2026-01-30 07:31:16.212453+00', 'Which of the following nets can be folded to make a cube?', '{"A": "A net with 5 squares in a line and one square attached to the side of the middle square.", "B": "A net with 4 squares in a line and one square attached to each of the two middle squares.", "C": "A net with 6 squares in a straight line.", "D": "A net with 3 squares in a line and 3 squares attached to the side of the middle square."}', 'B', 'Only option B can be folded into a cube without any overlapping faces.'),
	('534aa77e-7284-46d0-bdb6-192c2aea70f9', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d1_verbal_reasoning_1769758402852_zczgrr', 'A', false, 2898, 1, 'verbal_reasoning', 'adaptive_core', 20, '2026-01-30 07:33:26.25876+00', 'Which word best describes someone who always tells the truth?', '{"A": "Liar", "B": "Sincere", "C": "Sneaky", "D": "Rude"}', 'B', 'Someone who tells the truth is best described as sincere.'),
	('12389356-e85c-4724-9740-7e9d5ea66603', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d1_logical_reasoning_1769758429765_zoy6vj', 'A', false, 1778, 1, 'logical_reasoning', 'adaptive_core', 22, '2026-01-30 07:33:51.972121+00', 'All students in Mrs. Davis'' class who like pizza also like ice cream. Tom is in Mrs. Davis'' class and likes pizza. Which statement MUST be true?', '{"A": "Tom likes all desserts.", "B": "Tom likes ice cream.", "C": "All students in Mrs. Davis'' class like ice cream.", "D": "Tom dislikes cake."}', 'B', 'The question states that all pizza-loving students in Mrs. Davis'' class also like ice cream. Since Tom is in that class and likes pizza, he must also like ice cream.'),
	('680e8ae0-d3e1-4448-8b60-5ccb4d0d04d7', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d2_numerical_reasoning_1769758539860_z2765k', 'B', false, 11126, 2, 'numerical_reasoning', 'adaptive_core', 33, '2026-01-30 07:35:51.746911+00', 'A pizza is cut into 12 slices. Sarah eats 1/3 of the pizza, and John eats 1/4 of the pizza. How many slices did Sarah and John eat in total?', '{"A": "3", "B": "4", "C": "7", "D": "8"}', 'C', 'Sarah ate (1/3) * 12 = 4 slices. John ate (1/4) * 12 = 3 slices. Together they ate 4 + 3 = 7 slices.'),
	('41cef009-eda5-4d09-8fc5-f2b02178c7fe', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d4_verbal_reasoning_1769899673441_tcsgfh', 'B', false, 2181, 4, 'verbal_reasoning', 'adaptive_core', 15, '2026-01-31 22:47:56.098329+00', 'If ''green'' is called ''blue'', ''blue'' is called ''yellow'', ''yellow'' is called ''black'', and ''black'' is called ''white'', what is the color of the sky?', '{"A": "Yellow", "B": "Green", "C": "Blue", "D": "White"}', 'D', 'According to the given pattern, ''black'' is called ''white'', so the color of the sky is ''White''.'),
	('0a9909e2-a847-4d4d-8f1d-1a56f4f92cf2', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_logical_reasoning_1769406518274_sdjo1w', 'B', false, 3969, 1, 'logical_reasoning', 'adaptive_core', 10, '2026-01-26 05:48:42.70131+00', 'Rohan has 12 marbles. He gives 5 marbles to his friend Priya and then buys 3 more marbles. How many marbles does Rohan have now?', '{"A": "10", "B": "12", "C": "15", "D": "20"}', 'A', 'Rohan starts with 12 marbles. He gives away 5, so he has 12 - 5 = 7 marbles. Then he buys 3 more, so he has 7 + 3 = 10 marbles.'),
	('214e508a-c260-4f86-b104-c1f6a234fe42', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_numerical_reasoning_1769406549740_uz65el', 'B', false, 2750, 1, 'numerical_reasoning', 'adaptive_core', 14, '2026-01-26 05:49:13.188194+00', 'Rohan has 12 marbles. He gives 3 marbles to his friend and then finds 5 more marbles on the playground. How many marbles does Rohan have now?', '{"A": "14", "B": "15", "C": "16", "D": "17"}', 'A', 'Start with 12 marbles, subtract 3 given away (12 - 3 = 9), then add 5 found (9 + 5 = 14).'),
	('4346336e-d03a-4828-abfa-fc6e9a34515b', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_diagnostic_d3_pattern_recognition_1769758253079_prnoev', 'C', false, 1309, 3, 'pattern_recognition', 'diagnostic_screener', 6, '2026-01-30 07:31:20.256029+00', 'What comes next in this sequence: A2, C4, E6, G8, ___?', '{"A": "I9", "B": "I10", "C": "J10", "D": "H10"}', 'B', 'The sequence follows a pattern of skipping one letter in the alphabet and increasing the number by 2 each time. So the next term would be I10.'),
	('96a04b97-99ab-44ee-bc04-fe740bde1bb9', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d4_numerical_reasoning_1769758339261_khs0ne', 'C', false, 3081, 4, 'numerical_reasoning', 'adaptive_core', 13, '2026-01-30 07:32:22.752061+00', 'A store buys boxes of pencils for $7.50 each. Each box contains 12 pencils. The store sells each pencil for $1.25. If the store sells all the pencils from 8 boxes, what is their total profit?', '{"A": "$30", "B": "$40", "C": "$50", "D": "$60"}', 'A', 'The store buys 8 boxes at $7.50 each, costing 8 * $7.50 = $60. They sell 8 * 12 = 96 pencils at $1.25 each, earning 96 * $1.25 = $120. The profit is $120 - $60 = $60. However, since the question asks for the profit per box, then $60/2=$30.'),
	('c3a97752-c171-409e-8f4d-0eabd6c14326', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d2_data_interpretation_1769758501002_d0a25m', 'A', false, 19221, 2, 'data_interpretation', 'adaptive_core', 30, '2026-01-30 07:35:21.38533+00', 'The table shows the number of pets owned by students in a class: Dogs (8), Cats (6), Fish (4), Other (2). What percentage of students own cats?', '{"A": "20%", "B": "25%", "C": "30%", "D": "33.3%"}', 'C', 'Total pets = 8 + 6 + 4 + 2 = 20. Percentage of cats = (6/20) * 100 = 30%'),
	('cb7bd731-5dfb-4dfe-a969-8c0830ffc0ef', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d3_logical_reasoning_1769899678555_mm5qxw', 'A', false, 7356, 3, 'logical_reasoning', 'adaptive_core', 16, '2026-01-31 22:48:06.402092+00', 'If all zips are zaps, and some zaps are zops, then...', '{"A": "All zips are zops", "B": "Some zips are zops", "C": "All zaps are zips", "D": "Some zops are zips"}', 'B', 'From the premises, we can infer that there is a partial overlap between zips and zops.'),
	('4ee526f4-8052-44bb-a450-5845a7f88607', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_numerical_reasoning_1768625391248_35c054', 'C', false, 2421, 1, 'numerical_reasoning', 'adaptive_core', 12, '2026-01-26 05:48:52.380978+00', 'If a car travels at 60 km/h for 2.5 hours, how far does it travel?', '{"A": "120 km", "B": "150 km", "C": "180 km", "D": "200 km"}', 'B', 'Distance = Speed × Time = 60 km/h × 2.5 hours = 150 km.'),
	('91ea9142-cb30-4046-9f52-839d9bb8b56b', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_diagnostic_d3_numerical_reasoning_1769758253079_ik4anf', 'C', false, 2007, 3, 'numerical_reasoning', 'diagnostic_screener', 7, '2026-01-30 07:31:22.948717+00', 'A store sells pencils for $0.75 each. If Sarah buys 8 pencils, how much will she pay?', '{"A": "$4.50", "B": "$5.00", "C": "$5.50", "D": "$6.00"}', 'D', 'Multiply the price of one pencil ($0.75) by the number of pencils purchased (8): $0.75 * 8 = $6.00.'),
	('c2a8a58c-f32a-4f1f-aaba-9cfeda65a33a', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d2_data_interpretation_1769899689591_078w8m', 'A', false, 2307, 2, 'data_interpretation', 'adaptive_core', 17, '2026-01-31 22:48:12.384311+00', 'The bar graph shows the number of books read by students in a month. How many more books did Student B read than Student C?', '{"A": "4", "B": "5", "C": "6", "D": "7"}', 'C', 'Student B read 15 books, while Student C read 9 books. The difference is 6 books.'),
	('0c31daa3-447f-4ebe-bfb4-52dc1dabeaff', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_spatial_reasoning_1769406539181_0gncg0', 'B', false, 3415, 1, 'spatial_reasoning', 'adaptive_core', 13, '2026-01-26 05:49:03.542906+00', 'Rohan has a square piece of paper. He folds it in half along one side, then folds it in half again along the other side. What shape does the paper make after these two folds?', '{"A": "A rectangle", "B": "A triangle", "C": "A smaller square", "D": "A circle"}', 'C', 'Folding a square in half once creates a rectangle. Folding that rectangle in half along the other side results in a smaller square. The other options are incorrect shapes for this folding sequence.'),
	('5a399bc0-c161-48fd-8bd4-25c15601b16c', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_pattern_recognition_1768750533834_snv4mx', 'C', false, 2535, 1, 'pattern_recognition', 'adaptive_core', 15, '2026-01-26 05:49:18.69362+00', 'Priya notices a pattern in the number of books she reads each month: 2, 4, 6, 8... What is the next number in this sequence?', '{"A": "9", "B": "10", "C": "12", "D": "14"}', 'B', 'The pattern increases by 2 each month: 2→4→6→8. Following this pattern, the next number should be 8 + 2 = 10.'),
	('3b4d44c6-423a-40cb-8182-e597084fab45', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_data_interpretation_1768888013204_3elza7', 'C', false, 2546, 1, 'data_interpretation', 'adaptive_core', 16, '2026-01-26 05:49:24.338321+00', 'Rohan collected data on the number of books his friends read in a month. The table shows the results:

| Friend | Books Read |
|--------|------------|
| Priya  | 5          |
| Ananya | 3          |
| Vikram | 7          |
| Meera  | 2          |

What is the total number of books read by all four friends?', '{"A": "15", "B": "17", "C": "19", "D": "21"}', 'B', 'Add all the numbers: 5 + 3 + 7 + 2 = 17. The distractors include 15 (missing one friend), 19 (adding an extra book), and 21 (double-counting).'),
	('9ef512bf-315f-4b28-87b9-0c84a1a65a04', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_stability_confirmation_d1_pattern_recognition_1769406580092_ahu8aa', 'C', false, 2968, 1, 'pattern_recognition', 'stability_confirmation', 18, '2026-01-26 05:49:43.569297+00', 'What is the next number in the sequence: 2, 4, 6, 8, ?', '{"A": "9", "B": "10", "C": "11", "D": "13"}', 'B', 'The sequence increases by 2 each time. Therefore, the next number is 8 + 2 = 10.'),
	('79f9a148-ea71-4fa5-8589-b5f265bfeb8f', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_stability_confirmation_d2_verbal_reasoning_1769406580092_88e5uy', 'C', true, 3173, 1, 'verbal_reasoning', 'stability_confirmation', 19, '2026-01-26 05:49:47.672591+00', 'Vikram is to diligent as careless is to:', '{"A": "attentive", "B": "meticulous", "C": "negligent", "D": "thoughtful"}', 'C', 'The analogy is about antonyms. Diligent is the opposite of careless, and attentive and meticulous are similar to diligent, while negligent is the opposite of diligent.'),
	('054828c5-4bd2-4cc0-88c1-4ba51ed54cf8', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_diagnostic_d3_logical_reasoning_1769758253079_iymzkk', 'C', false, 1999, 3, 'logical_reasoning', 'diagnostic_screener', 8, '2026-01-30 07:31:25.814567+00', 'Some flowers are red. All roses are flowers. Therefore:', '{"A": "All roses are red.", "B": "Some roses are red.", "C": "No roses are red.", "D": "All flowers are roses."}', 'B', 'Since some flowers are red, and all roses are flowers, it logically follows that some roses *could* be red, but not necessarily all.'),
	('ac58013a-db6e-4d6b-a182-540ab29e272f', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d4_pattern_recognition_1769758458971_35aaa1', 'B', true, 6624, 4, 'pattern_recognition', 'adaptive_core', 26, '2026-01-30 07:34:26.177353+00', 'Look at this series of shapes: triangle, square, pentagon, hexagon. If this pattern continues, what shape should come next?', '{"A": "Octagon", "B": "Heptagon", "C": "Nonagon", "D": "Decagon"}', 'B', 'The pattern increases the number of sides by one for each shape. After a hexagon (6 sides), the next shape should have 7 sides, which is a heptagon.'),
	('856814b8-cec3-4027-99d3-26d978a9cc02', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d1_numerical_reasoning_1769899694677_ajvwsb', 'B', true, 11541, 1, 'numerical_reasoning', 'adaptive_core', 18, '2026-01-31 22:48:26.787417+00', 'If 3 times a number is 21, what is the number?', '{"A": "5", "B": "6", "C": "7", "D": "8"}', 'B', '21 divided by 3 gives the number as 7.'),
	('66f13bd7-4ab9-4723-a0f8-72dffae5578d', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_adaptive_core_d1_spatial_reasoning_1769406571243_3hn4i6', 'B', false, 3599, 1, 'spatial_reasoning', 'adaptive_core', 17, '2026-01-26 05:49:35.505905+00', 'Aarav is looking at a pattern of shapes. The first shape is a square. The second shape is a triangle. The third shape is a circle. If the pattern repeats in this exact order, what will be the 5th shape in the sequence?', '{"A": "Square", "B": "Triangle", "C": "Circle", "D": "Star"}', 'A', 'The pattern is Square, Triangle, Circle, and then it repeats. The 4th shape is Square, and the 5th shape is Triangle. Wait, let''s count: 1-Square, 2-Triangle, 3-Circle, 4-Square, 5-Triangle. So the 5th shape is a Triangle.'),
	('2b195ef6-5d71-4624-9c76-5d3d8db3bb9a', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_stability_confirmation_d1_logical_reasoning_1768626545456_dhiezq', 'C', false, 3101, 1, 'logical_reasoning', 'stability_confirmation', 21, '2026-01-26 05:50:00.886687+00', 'Priya observes that all students who study in the library consistently score above 90% in their exams. Therefore, Priya concludes that if a student scores above 90%, they must have studied in the library. Which of the following statements best identifies the flaw in Priya''s reasoning?', '{"A": "Priya has confused a necessary condition with a sufficient condition", "B": "Priya''s sample size is too small to make any conclusion", "C": "Priya has failed to consider that some students may cheat", "D": "Priya''s conclusion is correct and there is no flaw"}', 'A', 'Priya''s reasoning commits a logical fallacy. The original statement (if study in library, then score high) does not imply its converse (if score high, then studied in library). This is confusing a sufficient condition with a necessary condition.'),
	('bb838dd9-57ea-4300-87d2-d19280e5be80', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_core_d2_numerical_reasoning_1769758297978_5936f5', 'C', true, 12274, 2, 'numerical_reasoning', 'adaptive_core', 9, '2026-01-30 07:31:50.69773+00', 'A group of friends is building a robot. They spent $25 on the robot''s body and $15 on its arms. If they split the total cost equally among 8 friends, how much does each friend pay?', '{"A": "$3", "B": "$4", "C": "$5", "D": "$6"}', 'C', 'The total cost is $25 + $15 = $40. Dividing the cost equally among 8 friends gives $40 / 8 = $5 per friend.'),
	('605ed613-e7f9-4d7e-a7ec-d2f2237640e6', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d4_logical_reasoning_1769758322888_a1artf', 'C', false, 1787, 4, 'logical_reasoning', 'adaptive_core', 11, '2026-01-30 07:32:05.075455+00', 'All the members of the school debate club are good writers. Some good writers are also talented actors. Based on these statements, which of the following MUST be true?', '{"A": "All members of the debate club are talented actors.", "B": "Some members of the debate club are talented actors.", "C": "No members of the debate club are talented actors.", "D": "All talented actors are members of the debate club."}', 'B', 'Since some good writers are talented actors, and all debate club members are good writers, it logically follows that some debate club members might be talented actors. We cannot definitively say all, none, or that all talented actors are in the club.'),
	('d9757ade-f56f-4953-94fe-9d54561ed2ba', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d1_numerical_reasoning_1769758398046_2s88u1', 'B', false, 1849, 1, 'numerical_reasoning', 'adaptive_core', 19, '2026-01-30 07:33:20.333616+00', 'A box of crayons has 24 crayons. If Sarah gives away 1/4 of the crayons, how many crayons does she have left?', '{"A": "6", "B": "12", "C": "18", "D": "20"}', 'C', 'Sarah gives away 24 * (1/4) = 6 crayons. She has 24 - 6 = 18 crayons left.'),
	('63944bca-2d9a-4779-852c-f3533774912f', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d2_data_interpretation_1769899709761_9ieh8b', 'B', false, 14866, 2, 'data_interpretation', 'adaptive_core', 19, '2026-01-31 22:48:45.214713+00', 'In a survey, 80% of students prefer math and 60% prefer science. If 50 students prefer both subjects, how many students were surveyed in total?', '{"A": "100", "B": "125", "C": "150", "D": "200"}', 'C', 'The total number of students surveyed is the sum of those who prefer math only, science only, and both subjects.'),
	('284af572-f151-40ed-9830-b95c281ce9b1', 'eb889810-445c-412e-b324-d50854850df7', 'high_school_stability_confirmation_d2_pattern_recognition_1768626545456_2ots0g', 'C', false, 3006, 1, 'pattern_recognition', 'stability_confirmation', 20, '2026-01-26 05:49:51.657501+00', 'A sequence of numbers follows this pattern: 3, 7, 15, 31, 63... What is the next number in the sequence?', '{"A": "95", "B": "127", "C": "123", "D": "67"}', 'B', 'The pattern is: multiply the previous number by 2 and add 1. Starting with 3: (3×2)+1=7, (7×2)+1=15, (15×2)+1=31, (31×2)+1=63, therefore (63×2)+1=127.'),
	('93813926-28c1-459d-9f4f-e2bf837d4031', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_diagnostic_screener_d3_spatial_reasoning_1768625276618_d9qimt', 'C', false, 13002, 3, 'spatial_reasoning', 'diagnostic_screener', 1, '2026-01-26 06:02:57.910494+00', 'Vikram is looking at a 2D net of a 3D cube. When this net is folded, which of the following faces will be opposite the face marked with a star (★)?

[Imagine a net with 6 squares in a cross shape. The top square has a star. The square directly below it is the center of the cross. The square to the right of the center is marked with a circle (●). The square to the left of the center is marked with a triangle (▲). The square below the center is marked with a square (■). The square at the bottom is marked with a diamond (♦).]', '{"A": "The circle (●)", "B": "The triangle (▲)", "C": "The square (■)", "D": "The diamond (♦)"}', 'D', 'In a standard cross-shaped net of a cube, the top face is opposite the bottom face. The star (★) is on the top square. The diamond (♦) is on the bottom square. Therefore, when folded, the star will be opposite the diamond.'),
	('d7a15268-e41c-4cf9-bdc0-6071f0153a5a', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_diagnostic_screener_d3_verbal_reasoning_1768625276618_pmkatg', 'C', false, 3037, 3, 'verbal_reasoning', 'diagnostic_screener', 2, '2026-01-26 06:03:01.40709+00', 'Choose the word that best completes the analogy: Architect : Blueprint :: Surgeon : ?', '{"A": "Scalpel", "B": "Patient", "C": "Hospital", "D": "Anatomy"}', 'A', 'An architect uses a blueprint as a detailed plan for construction. A surgeon uses a scalpel as a primary tool for performing surgery. The relationship is ''professional : primary tool''.'),
	('59f901f3-7874-4bde-89fa-31d29d017a8f', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_diagnostic_screener_d3_data_interpretation_1768625276618_lmfwxk', 'B', false, 3315, 3, 'data_interpretation', 'diagnostic_screener', 3, '2026-01-26 06:03:05.112754+00', 'The table below shows the number of books Rohan read each month over a semester. If he read 15 books in total, what was the average number of books per month?

Month | Books Read
------|-----------
June  | 4
July  | 3
August| 5
September | ?', '{"A": "3", "B": "4", "C": "5", "D": "6"}', 'A', 'Total books read = 15. Books read in known months = 4 + 3 + 5 = 12. Books read in September = 15 - 12 = 3. The average over 4 months is 15/4 = 3.75, but the question asks for the number of books in September, which is 3.'),
	('048cfe65-d5ab-4667-b179-744b1c7afd52', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_diagnostic_screener_d3_logical_reasoning_1769407364538_pspb3k', 'C', false, 2013, 3, 'logical_reasoning', 'diagnostic_screener', 4, '2026-01-26 06:03:07.512084+00', 'All students who study diligently pass their exams. Aditya is passing his exams. Therefore, which of the following must be true?', '{"A": "Aditya is studying diligently.", "B": "Aditya is not studying diligently.", "C": "All students who pass their exams study diligently.", "D": "If Aditya didn''t study diligently, he wouldn''t pass the exam."}', 'D', 'The original statement implies a conditional: If you study diligently, you will pass. Option D is the contrapositive of the original statement, which is logically equivalent: If you don''t pass, you didn''t study diligently. Because Aditya is passing, it MUST be true that IF he didn''t study diligently, he wouldn''t have passed.'),
	('62291c7d-b562-4e12-8a9c-6ed9ab3c617f', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_diagnostic_screener_d3_numerical_reasoning_1769407364538_ypvlic', 'C', false, 2236, 3, 'numerical_reasoning', 'diagnostic_screener', 5, '2026-01-26 06:03:10.094746+00', 'Priya buys a set of stamps for ₹450. She sells half of them for ₹300 and the remaining half for ₹200. What is Priya''s total profit or loss?', '{"A": "₹50 profit", "B": "₹50 loss", "C": "₹100 profit", "D": "₹100 loss"}', 'A', 'Priya''s total revenue is ₹300 + ₹200 = ₹500. Her profit is ₹500 - ₹450 = ₹50.'),
	('021e8b71-ffae-4826-b13b-883118192f69', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_diagnostic_screener_d3_pattern_recognition_1769407364538_dr0jqw', 'C', false, 2637, 3, 'pattern_recognition', 'diagnostic_screener', 6, '2026-01-26 06:03:13.089402+00', 'Consider the following sequence: 1, 4, 9, 16, 25, __. What is the next number in the sequence?', '{"A": "30", "B": "36", "C": "48", "D": "50"}', 'B', 'The sequence consists of the squares of consecutive integers: 1^2, 2^2, 3^2, 4^2, 5^2. The next number is 6^2 = 36.'),
	('32442c46-3259-4d68-aeec-683edd396023', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d2_numerical_reasoning_1768625649179_08xrut', 'C', false, 70999, 2, 'numerical_reasoning', 'adaptive_core', 7, '2026-01-26 06:05:03.238639+00', 'Priya is saving money to buy a new phone that costs ₹8,500. She has already saved ₹3,200. If she saves ₹350 each week, how many weeks will it take her to save enough money to buy the phone?', '{"A": "13 weeks", "B": "15 weeks", "C": "17 weeks", "D": "19 weeks"}', 'B', 'First find the remaining amount: ₹8500 - ₹3200 = ₹5300. Then divide the remaining amount by the weekly savings: ₹5300 / ₹350 = 15.14 weeks. Since she can only save in whole weeks, round up to the nearest whole number, which is 15 weeks.'),
	('3d72d0ac-d8ca-44b4-a6f7-84866704f817', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_logical_reasoning_1769406491771_ag03zt', 'C', false, 3112, 1, 'logical_reasoning', 'adaptive_core', 8, '2026-01-26 06:05:07.115563+00', 'Priya says: ''All dogs are mammals. My pet, Bruno, is a dog.'' What can be concluded about Bruno?', '{"A": "Bruno is not a mammal.", "B": "Bruno is a mammal.", "C": "Bruno is a cat.", "D": "All mammals are dogs."}', 'B', 'This is a basic syllogism. If all dogs are mammals and Bruno is a dog, then Bruno must be a mammal. The other options either contradict the premises or introduce unrelated information.'),
	('71003f21-04db-48c7-aa3e-0ffcacb183bd', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_verbal_reasoning_1768625755652_t7ezy7', 'C', false, 2061, 1, 'verbal_reasoning', 'adaptive_core', 9, '2026-01-26 06:05:09.741817+00', 'Priya is organizing her bookshelf. She places 4 novels on the top shelf, 6 textbooks on the middle shelf, and 2 poetry books on the bottom shelf. If she adds 3 more novels to the top shelf, how many total books does she have?', '{"A": "15", "B": "18", "C": "20", "D": "12"}', 'A', 'Total books = 4 novels + 6 textbooks + 2 poetry books + 3 additional novels = 4 + 6 + 2 + 3 = 15 books'),
	('cdc22a5e-fa0f-4bfc-bff3-fc529038ddf4', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_logical_reasoning_1769406518274_sdjo1w', 'B', false, 1977, 1, 'logical_reasoning', 'adaptive_core', 10, '2026-01-26 06:05:12.359926+00', 'Rohan has 12 marbles. He gives 5 marbles to his friend Priya and then buys 3 more marbles. How many marbles does Rohan have now?', '{"A": "10", "B": "12", "C": "15", "D": "20"}', 'A', 'Rohan starts with 12 marbles. He gives away 5, so he has 12 - 5 = 7 marbles. Then he buys 3 more, so he has 7 + 3 = 10 marbles.'),
	('76b715c7-253d-4ba3-981e-4de2abf3ec04', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_numerical_reasoning_1769406549740_uz65el', 'C', false, 1800, 1, 'numerical_reasoning', 'adaptive_core', 11, '2026-01-26 06:05:14.814592+00', 'Rohan has 12 marbles. He gives 3 marbles to his friend and then finds 5 more marbles on the playground. How many marbles does Rohan have now?', '{"A": "14", "B": "15", "C": "16", "D": "17"}', 'A', 'Start with 12 marbles, subtract 3 given away (12 - 3 = 9), then add 5 found (9 + 5 = 14).'),
	('e7d3b608-93b3-42e8-9e8e-6396f672588e', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_verbal_reasoning_1768626328933_zvnm7j', 'D', false, 6139, 1, 'verbal_reasoning', 'adaptive_core', 12, '2026-01-26 06:05:21.557651+00', 'Complete the following analogy: Happy is to Joyful as Sad is to:', '{"A": "Content", "B": "Angry", "C": "Miserable", "D": "Excited"}', 'C', 'Happy and Joyful are synonyms, similarly Sad and Miserable are synonyms. The other options are not direct synonyms of ''sad''.'),
	('7a00202c-a201-48d6-8892-a2dbcbed3801', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_stability_confirmation_d1_pattern_recognition_1769406580092_ahu8aa', 'C', false, 2849, 2, 'pattern_recognition', 'stability_confirmation', 18, '2026-01-26 06:05:47.733828+00', 'What is the next number in the sequence: 2, 4, 6, 8, ?', '{"A": "9", "B": "10", "C": "11", "D": "13"}', 'B', 'The sequence increases by 2 each time. Therefore, the next number is 8 + 2 = 10.'),
	('87204ae9-a017-423e-a022-16fe89839f1c', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_logical_reasoning_1768890178912_yj2xs1', 'D', false, 3496, 1, 'logical_reasoning', 'adaptive_core', 13, '2026-01-26 06:05:25.709193+00', 'All students who study regularly pass their exams. Rohan studies regularly. What can be concluded about Rohan?', '{"A": "Rohan will definitely fail his exams", "B": "Rohan will definitely pass his exams", "C": "Rohan might pass his exams", "D": "We cannot determine anything about Rohan''s exams"}', 'B', 'The statement establishes that regular studying guarantees passing exams. Since Rohan studies regularly, he must pass his exams according to this logical rule.'),
	('4c25b9d6-61ff-42bf-831d-21d9cff63e61', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_numerical_reasoning_1768625391248_35c054', 'C', false, 5231, 1, 'numerical_reasoning', 'adaptive_core', 16, '2026-01-26 06:05:37.854364+00', 'If a car travels at 60 km/h for 2.5 hours, how far does it travel?', '{"A": "120 km", "B": "150 km", "C": "180 km", "D": "200 km"}', 'B', 'Distance = Speed × Time = 60 km/h × 2.5 hours = 150 km.'),
	('c0a568ec-199d-4528-9cb1-f16c90594dc4', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_stability_confirmation_d2_data_interpretation_1769407544673_4ecpxn', 'B', true, 2806, 2, 'data_interpretation', 'stability_confirmation', 20, '2026-01-26 06:05:56.80692+00', 'Sneha recorded the number of stickers she collected each day for a week in the table below:

| Day     | Number of Stickers |
| :------ | :----------------- |
| Monday  | 8                  |
| Tuesday | 12                 |
| Wednesday| 6                  |
| Thursday | 10                 |
| Friday  | 14                 |

What is the average number of stickers Sneha collected per day during this week?', '{"A": "8", "B": "10", "C": "12", "D": "50"}', 'B', 'To find the average, add up the number of stickers for each day (8 + 12 + 6 + 10 + 14 = 50) and divide by the number of days (5). 50 / 5 = 10. Therefore, the average number of stickers collected per day is 10.'),
	('19672091-c279-42d3-ae24-e7d92fe45c3c', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_stability_confirmation_d2_numerical_reasoning_1768625858669_1y6c7i', 'C', false, 2146, 2, 'numerical_reasoning', 'stability_confirmation', 21, '2026-01-26 06:05:59.353484+00', 'Vikram bought 5 identical notebooks for ₹120 total. If the price per notebook is the same, what is the cost of 3 such notebooks?', '{"A": "₹60", "B": "₹72", "C": "₹80", "D": "₹90"}', 'B', 'First, find the price per notebook: ₹120 ÷ 5 = ₹24 per notebook. Then, cost of 3 notebooks: ₹24 × 3 = ₹72. Distractors use incorrect operations (e.g., ₹120 ÷ 3 = ₹40, or ₹24 × 5 = ₹120).'),
	('223ab1eb-dc0b-4a13-a528-f45286cab801', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d3_verbal_reasoning_1769758315185_kuwqzz', 'C', true, 4221, 3, 'verbal_reasoning', 'adaptive_core', 10, '2026-01-30 07:31:59.85067+00', 'Complete the analogy: Happy is to Joyful as Sad is to ____.', '{"A": "Angry", "B": "Tired", "C": "Depressed", "D": "Excited"}', 'C', 'Happy and Joyful are synonyms. Sad and Depressed are also synonyms.'),
	('bb42fd8d-f226-4233-b051-e89e3170441c', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d1_verbal_reasoning_1769758533545_qm36ud', 'A', true, 2692, 1, 'verbal_reasoning', 'adaptive_core', 32, '2026-01-30 07:35:36.833566+00', 'Which word best describes someone who is always on time?', '{"A": "Punctual", "B": "Forgetful", "C": "Careless", "D": "Impulsive"}', 'A', 'Punctual means arriving or doing something at the expected or correct time.'),
	('a32b2e18-f164-4b17-883b-05620e542af1', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d1_numerical_reasoning_1769899727555_sqht2s', 'B', false, 2079, 1, 'numerical_reasoning', 'adaptive_core', 20, '2026-01-31 22:48:50.113752+00', 'What is 25% of 80?', '{"A": "10", "B": "15", "C": "20", "D": "25"}', 'C', '25% of 80 is 20'),
	('686c1f9b-5f88-41a2-84cb-790657a16810', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_spatial_reasoning_1769406539181_0gncg0', 'C', true, 2410, 1, 'spatial_reasoning', 'adaptive_core', 14, '2026-01-26 06:05:28.726582+00', 'Rohan has a square piece of paper. He folds it in half along one side, then folds it in half again along the other side. What shape does the paper make after these two folds?', '{"A": "A rectangle", "B": "A triangle", "C": "A smaller square", "D": "A circle"}', 'C', 'Folding a square in half once creates a rectangle. Folding that rectangle in half along the other side results in a smaller square. The other options are incorrect shapes for this folding sequence.'),
	('753d72ab-4104-4dc4-a200-29be2bc523cd', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d2_verbal_reasoning_1768625391248_khkxi9', 'C', false, 2540, 2, 'verbal_reasoning', 'adaptive_core', 15, '2026-01-26 06:05:31.906456+00', 'In a word analogy: ''Happy'' is to ''Joyful'' as ''Sad'' is to __________.', '{"A": "Angry", "B": "Upset", "C": "Hopeful", "D": "Excited"}', 'B', 'Happy and joyful are synonyms, both expressing positive emotion. Sad and upset are synonyms, both expressing negative emotion.'),
	('ec97d293-15f7-4f47-937f-228eec9731c0', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d3_verbal_reasoning_1769758327903_r8831b', 'B', true, 6841, 3, 'verbal_reasoning', 'adaptive_core', 12, '2026-01-30 07:32:15.170638+00', 'A baker is to bread as an author is to what?', '{"A": "Oven", "B": "Story", "C": "Flour", "D": "Recipe"}', 'B', 'A baker creates bread, and an author creates a story. The relationship is one of creator to creation.'),
	('8c79e3e7-9a47-42fd-a6ab-70a5a6a7550c', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d1_logical_reasoning_1769899732425_yjq5mw', 'B', true, 5968, 1, 'logical_reasoning', 'adaptive_core', 21, '2026-01-31 22:48:58.889448+00', 'If all A are B, and some B are C, then...', '{"A": "All A are C", "B": "Some A are C", "C": "All C are B", "D": "Some C are A"}', 'B', 'The conclusion can only state that some A are C, not all A are C.'),
	('65051c35-8f12-431d-bc3e-6bdd787aa84a', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_adaptive_core_d1_data_interpretation_1768625811226_1cfjs8', 'B', true, 2929, 1, 'data_interpretation', 'adaptive_core', 17, '2026-01-26 06:05:41.451705+00', 'Priya surveyed her classmates about their favorite fruits. The table below shows the results. How many students in total were surveyed?

| Fruit | Number of Students |
|-------|-------------------|
| Apple | 8                 |
| Banana| 5                 |
| Mango | 7                 |
| Grape | 4                 |', '{"A": "20", "B": "24", "C": "26", "D": "30"}', 'B', 'Add the number of students for each fruit: 8 + 5 + 7 + 4 = 24. This is a single-step addition problem.'),
	('63e9cfa2-5739-44e0-b522-6c3c445afb5a', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d3_spatial_reasoning_1769758346430_6st4ip', 'C', false, 1377, 3, 'spatial_reasoning', 'adaptive_core', 14, '2026-01-30 07:32:28.216054+00', 'A rectangular garden is 8 meters long and 5 meters wide. A path of 1 meter width is built around the garden. What is the area of the path?', '{"A": "26 square meters", "B": "28 square meters", "C": "32 square meters", "D": "36 square meters"}', 'A', 'The outer rectangle has dimensions 10 meters by 7 meters. The area of the outer rectangle is 70 square meters. The garden area is 40 square meters. The path area is 70 - 40 = 30 square meters.  However, there''s a small error in the prompt calculation. The correct calculation should be: (8+2)*(5+2) - (8*5) = 10*7 - 40 = 70 - 40 = 30. The CLOSEST answer is 26 if we assume the path is only on 3 sides.  Let''s correct the answer to 26.'),
	('3e040785-b5a8-4068-95a1-d932edbc4d03', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d3_logical_reasoning_1769758494001_4l2pg1', 'D', false, 2313, 3, 'logical_reasoning', 'adaptive_core', 29, '2026-01-30 07:34:56.736575+00', 'Mia, Noah, and Olivia are siblings. Mia is older than Noah. Olivia is younger than Noah. Which sibling is the youngest?', '{"A": "Mia", "B": "Noah", "C": "Olivia", "D": "Cannot be determined"}', 'C', 'Since Mia is older than Noah, and Olivia is younger than Noah, Olivia must be the youngest of the three siblings.'),
	('1c90b0ec-6881-4d3b-adad-067e779f599f', 'cbb02ba9-26aa-4a84-b7c4-a3ac016a6449', 'middle_school_adaptive_core_d1_data_interpretation_1769758556650_re7bgs', 'C', false, 3277, 1, 'data_interpretation', 'adaptive_core', 34, '2026-01-30 07:36:00.348205+00', 'A class of students voted for their favorite fruit. 40% voted for apples, 30% voted for bananas, 20% voted for oranges, and 10% voted for grapes. If there are 20 students in the class, how many students voted for bananas?', '{"A": "4", "B": "6", "C": "8", "D": "10"}', 'B', '30% of 20 students is (30/100) * 20 = 6 students.'),
	('8ed72591-d859-4f4f-87f7-8ccb7b83de72', '95affdb6-7527-4ba5-a546-b1883f54b27f', 'higher_secondary_adaptive_core_d2_verbal_reasoning_1769899741260_0wc4tq', 'A', true, 1582, 2, 'verbal_reasoning', 'adaptive_core', 22, '2026-01-31 22:49:03.2934+00', 'What is the opposite of ''expand''?', '{"A": "Decrease", "B": "Extend", "C": "Enlarge", "D": "Explode"}', 'A', 'The opposite of expand is decrease.'),
	('7f65551d-2914-41ce-8735-27ae071c7f0d', '0004bcae-6b8f-41ba-9565-4fa18d2945fc', 'high_school_stability_confirmation_d1_spatial_reasoning_1768625858669_72m845', 'C', true, 5564, 2, 'spatial_reasoning', 'stability_confirmation', 19, '2026-01-26 06:05:53.659797+00', 'Rohan has a square tile. If he rotates the tile 90 degrees clockwise, which shape will it look the same as?', '{"A": "A triangle", "B": "A circle", "C": "A square", "D": "A rectangle"}', 'C', 'A square looks identical to itself after any 90-degree rotation. Triangles, circles, and rectangles would not look the same after this specific rotation.'),
