	('880b79cd-787f-44f4-ab58-1a1de90a644d', '6521b4af-de4e-4a3d-a67e-b9ae8ad93277', 'high_school_adaptive_core_d1_verbal_reasoning_1769496535352_r3unjw', 'C', false, 1898, 1, 'verbal_reasoning', 'adaptive_core', 18, '2026-01-27 06:48:58.122285+00', 'Choose the word most similar to "ABUNDANT":', '{"A": "Scarce", "B": "Plentiful", "C": "Empty", "D": "Small"}', 'B', 'Fallback question'),
	('fabab4fc-2154-44ad-849d-44e9e0ef911f', '6521b4af-de4e-4a3d-a67e-b9ae8ad93277', 'high_school_adaptive_core_d1_logical_reasoning_1768890178912_yj2xs1', 'C', false, 2544, 1, 'logical_reasoning', 'adaptive_core', 19, '2026-01-27 06:49:02.592659+00', 'All students who study regularly pass their exams. Rohan studies regularly. What can be concluded about Rohan?', '{"A": "Rohan will definitely fail his exams", "B": "Rohan will definitely pass his exams", "C": "Rohan might pass his exams", "D": "We cannot determine anything about Rohan''s exams"}', 'B', 'The statement establishes that regular studying guarantees passing exams. Since Rohan studies regularly, he must pass his exams according to this logical rule.'),
