	('73777049-0b9b-4891-b122-b3818f5ce696', 'd0f35510-1e79-4bee-8b0e-b581f62bf9ae', 'middle_school_diagnostic_d3_numerical_reasoning_1769754696915_b3xzmt', 'B', true, 1549, 3, 'numerical_reasoning', 'diagnostic_screener', 3, '2026-02-02 05:38:54.332865+00', 'A bakery sells 480 cupcakes in a day. If they are packed in boxes of 12, how many boxes are needed?', '{"A": "36", "B": "40", "C": "48", "D": "60"}', 'B', 'Divide total cupcakes by cupcakes per box: 480 / 12 = 40'),
