	('64a41971-7f47-4d06-a246-b79a76b3fe0e', '2171cfd8-7e54-4468-8c79-71dad2654991', 'middle_school_diagnostic_d3_spatial_reasoning_1769754696932_2qnwqv', 'B', false, 12609, 3, 'spatial_reasoning', 'diagnostic_screener', 1, '2026-02-02 06:21:46.533216+00', 'Imagine a cube with each side being 6 units long. What is the volume of this cube?', '{"A": "60 cubic units", "B": "120 cubic units", "C": "180 cubic units", "D": "216 cubic units"}', 'D', 'The volume of a cube is calculated by cubing the length of one side: 6^3 = 216 cubic units'),
	('77d72db4-286d-4fea-aa1a-6f4b6530f53c', '2171cfd8-7e54-4468-8c79-71dad2654991', 'middle_school_core_d2_data_interpretation_1769755658288_l5e5kg', 'B', true, 3707, 2, 'data_interpretation', 'adaptive_core', 15, '2026-02-02 06:25:12.794987+00', 'The following table shows the number of books read by students in a class during the summer. Amy: 5, Ben: 8, Carol: 3, David: 6. What is the average number of books read?', '{"A": "4", "B": "5.5", "C": "6", "D": "7"}', 'B', 'The total number of books read is 5 + 8 + 3 + 6 = 22. The average is 22 / 4 = 5.5.'),
