	('7ca8d63a-c803-4a95-aa76-b5063f304c88', '9861d060-4fe8-4e5d-8fb6-085e651961b5', 'middle_school_adaptive_core_d5_spatial_reasoning_1770028106918_2gq9vu', 'C', true, 3331, 5, 'spatial_reasoning', 'adaptive_core', 10, '2026-02-02 10:28:30.836929+00', 'How many corners does a rectangle have?', '{"A": "2", "B": "3", "C": "4", "D": "5"}', 'C', 'Fallback question'),
	('5720b748-2640-4f22-b947-0ec3ebb19ab7', '9861d060-4fe8-4e5d-8fb6-085e651961b5', 'middle_school_adaptive_core_d2_logical_reasoning_1769754856181_gsyku6', 'A', false, 142588, 2, 'logical_reasoning', 'adaptive_core', 16, '2026-02-02 10:43:18.489023+00', 'A bookshelf has 5 shelves, and each shelf can hold 3 rows of books. If the bookshelf is currently empty, how many books can be placed on it in total if each row can hold 8 books?', '{"A": "80", "B": "120", "C": "100", "D": "60"}', 'B', 'To find the total number of books the bookshelf can hold, we first calculate the total number of rows (5 shelves * 3 rows/shelf = 15 rows), then multiply by the number of books each row can hold (15 rows * 8 books/row = 120 books).'),
	('ec81ddaa-5744-444f-9565-542f47d1ae08', '9861d060-4fe8-4e5d-8fb6-085e651961b5', 'middle_school_adaptive_core_d1_data_interpretation_1769754887313_zr4vds', 'A', false, 140337, 1, 'data_interpretation', 'adaptive_core', 17, '2026-02-02 10:45:40.242455+00', 'A bookshelf has 5 shelves, and each shelf can hold 8 books. If the bookshelf is currently empty, how many books can be placed on it in total?', '{"A": "20", "B": "30", "C": "40", "D": "50"}', 'C', 'To find the total number of books that can be placed, multiply the number of shelves by the number of books each shelf can hold: 5 shelves * 8 books/shelf = 40 books'),
	('bb84c38f-e2d3-4585-be99-dcba39516d34', '9861d060-4fe8-4e5d-8fb6-085e651961b5', 'middle_school_stability_d4_data_interpretation_1769769221231_37i49a', 'A', false, 161698, 1, 'data_interpretation', 'stability_confirmation', 20, '2026-02-02 10:53:14.285705+00', 'The chart shows the number of students participating in different after-school activities: Sports (45), Music (30), Art (25), Drama (20). What percentage of the total number of participants are involved in Music?', '{"A": "20%", "B": "25%", "C": "30%", "D": "35%"}', 'B', 'Total participants: 45 + 30 + 25 + 20 = 120. Percentage in Music: (30/120) * 100 = 25%'),
