	('8462574f-6b96-4f89-a4d0-2412fb1feea1', '0ede676a-04f8-4a2f-b944-38dfb9a812b6', 'higher_secondary_adaptive_core_d2_numerical_reasoning_1769896702219_bnblm4', 'A', false, 10658, 2, 'numerical_reasoning', 'adaptive_core', 20, '2026-01-31 21:58:33.403022+00', 'If a bus travels 120 miles in 3 hours, how many miles does it travel in 5 hours?', '{"A": "150", "B": "180", "C": "200", "D": "220"}', 'B', 'The bus travels 40 miles per hour. In 5 hours, it covers 40 * 5 = 200 miles.'),
