	('59c261b8-3eea-4c1f-97fc-7ed8464ad85e', '685f1f2e-35f4-4b7c-85e3-a42a657328fa', 'higher_secondary_diagnostic_d3_numerical_reasoning_1769897350223_kulyxt', 'C', false, 29347, 3, 'numerical_reasoning', 'diagnostic_screener', 1, '2026-01-31 22:09:40.106968+00', 'If a = 5 and b = 3, what is 2a + 3b?', '{"A": "13", "B": "16", "C": "19", "D": "22"}', 'B', 'Substitute a=5 and b=3, then calculate: 2(5) + 3(3) = 10 + 9 = 19'),
	('22960ca8-b083-48aa-8f7d-0f0a4809361b', '685f1f2e-35f4-4b7c-85e3-a42a657328fa', 'higher_secondary_diagnostic_d3_spatial_reasoning_1769897350224_sg5mzk', 'C', false, 1451, 3, 'spatial_reasoning', 'diagnostic_screener', 4, '2026-01-31 22:09:48.145553+00', 'Which shape is the odd one out?', '{"A": "Square", "B": "Circle", "C": "Triangle", "D": "Rectangle"}', 'B', 'All other shapes have straight sides, while a circle has a curved boundary.'),
	('a6241a9b-1ea9-4a19-8a26-2da5c8f6feff', '685f1f2e-35f4-4b7c-85e3-a42a657328fa', 'higher_secondary_stability_dundefined_logical_reasoning_1769897486465_qoephh', 'C', false, 3850, 1, 'logical_reasoning', 'stability_confirmation', 22, '2026-01-31 22:11:36.331606+00', 'Which shape completes the pattern: ◯, △, ◻, □, ___?', '{"A": "■", "B": "◇", "C": "★", "D": "●"}', 'A', 'The pattern alternates between circle, triangle, square, and rectangle, so the next shape is a square (■).'),
	('f48c3fdb-ca7e-45f7-bde6-272f07f91cf6', '685f1f2e-35f4-4b7c-85e3-a42a657328fa', 'higher_secondary_stability_dundefined_verbal_reasoning_1769897486465_6iiimm', 'A', true, 3540, 1, 'verbal_reasoning', 'stability_confirmation', 23, '2026-01-31 22:11:41.103925+00', 'In a data set, the mean is 15, median is 18, and mode is 20. What can be said about the data?', '{"A": "Positively skewed", "B": "Negatively skewed", "C": "Symmetric", "D": "Bimodal"}', 'A', 'With mean < median < mode, the data is positively skewed.'),
