	('10d241f2-45f8-41f2-bad3-a985d6abba8c', '7fd94041-fec4-4df6-88b7-cd9650fb1cb3', 'higher_secondary_adaptive_core_d3_logical_reasoning_1769687662250_reo1kr', 'A', false, 106787, 3, 'logical_reasoning', 'adaptive_core', 40, '2026-01-29 11:56:07.413324+00', 'If it rains, the ground gets wet. The ground is wet. What can we conclude?', '{"A": "It definitely rained", "B": "It might have rained", "C": "It did not rain", "D": "The sun is shining"}', 'B', 'Fallback question'),
	('709733d1-e2ee-43a6-a514-c12418d92512', '7fd94041-fec4-4df6-88b7-cd9650fb1cb3', 'higher_secondary_adaptive_core_d2_pattern_recognition_1769687773978_5rwq81', 'B', true, 83891, 1, 'pattern_recognition', 'adaptive_core', 42, '2026-01-29 11:57:36.455878+00', 'What comes next: 2, 4, 8, 16, ?', '{"A": "24", "B": "32", "C": "20", "D": "18"}', 'B', 'Fallback question'),
